import type { Question } from './types'
import { makeQuestionBank } from './base'

export function buildUniversityAcademicQuestionCatalog(): Record<string, Question[]> {
  return {
  microeconomics: makeQuestionBank('University', [
    { id: 16101, chapter: 'Microeconomics Dock', title: 'Demand law', prompt: 'All else equal, when price rises, quantity demanded usually:', correct: 'Falls', wrong: [['Rises', 'That reverses the usual demand relationship.', 'Keep the law of demand straight.'], ['Stays permanently identical', 'Quantity demanded usually responds to price changes.', 'This is not a fixed relationship.'], ['Becomes a tax', 'That mixes concepts.', 'Focus on quantity demanded.']] },
    { id: 16102, chapter: 'Microeconomics Reef', title: 'Marginal idea', prompt: 'Marginal cost means:', correct: 'The cost of producing one more unit', wrong: [['The cost of the whole factory forever', 'That is too broad.', 'Marginal means one additional unit.'], ['Only advertising cost', 'Marginal cost is not one special expense type.', 'Think incremental production cost.'], ['A profit target', 'Cost and profit are different concepts.', 'Stay with extra cost.']] },
    { id: 16103, chapter: 'Microeconomics Cove', title: 'Market structure', prompt: 'A monopoly is a market with:', correct: 'One dominant seller', wrong: [['Thousands of identical sellers', 'That sounds more like perfect competition.', 'Monopoly means one seller.'], ['Only buyers and no sellers', 'That is not a functioning market structure.', 'A seller must exist.'], ['Exactly two firms', 'That is a duopoly.', 'One seller is the key clue.']] },
    { id: 16104, chapter: 'Microeconomics Lagoon', title: 'Consumer surplus', prompt: 'Consumer surplus is roughly:', correct: 'The gap between what buyers would pay and what they actually pay', wrong: [['A tax paid by the producer', 'That is not consumer surplus.', 'Think buyer benefit from paying less than willingness to pay.'], ['The cost of manufacturing goods', 'That belongs to producers.', 'This is a buyer-side concept.'], ['A loan from a bank', 'That is unrelated.', 'Use willingness-to-pay language.']] },
    { id: 16105, chapter: 'Basic Concepts', title: 'Opportunity Cost', prompt: 'If you spend $10 and 2 hours watching a movie instead of working for $15/hour, what is your total economic cost?', correct: '$40', wrong: [["$10", "You forgot the cost of your time.", "Opportunity cost includes both explicit and implicit costs."], ["$30", "You only counted the lost wages.", "Don't forget the $10 you actually spent."], ["$25", "You added the wage and the ticket once, but the time is 2 hours.", "2 hours at $15 is $30, plus $10 ticket."]] },
    { id: 16106, chapter: 'Supply and Demand', title: 'Shift vs Movement', prompt: 'An increase in the price of beef will cause what change in the market for beef?', correct: 'A movement along the demand curve', wrong: [["A leftward shift of the demand curve", "Price changes cause movements along the curve, not shifts of the curve.", "Distinguish between change in quantity demanded and change in demand."], ["A rightward shift of the supply curve", "Price of the good itself doesn't shift its own supply curve.", "Only external factors like input prices shift the curve."], ["No change at all", "Price changes always affect the quantity people want to buy.", "The law of demand still applies."]] },
    { id: 16107, chapter: 'Basic Concepts', title: 'Scarcity', prompt: 'Scarcity exists because:', correct: 'Resources are limited but wants are unlimited', wrong: [["People are too greedy", "Scarcity is a physical reality of resources, not just a moral failing.", "Even if people were less greedy, resources would still be finite."], ["The government restricts production", "While it can happen, scarcity is a fundamental problem in all systems.", "Think about the total amount of land or minerals available."], ["Prices are too high", "High prices are a signal of scarcity, not the cause of it.", "If resources were infinite, prices would be zero."]] },
    { id: 16108, chapter: 'Supply and Demand', title: 'Normal Goods', prompt: 'If consumer income rises and the demand for generic cereal falls, generic cereal is a(n):', correct: 'Inferior good', wrong: [["Normal good", "Normal goods see demand rise when income rises.", "Inferior goods are replaced as people get wealthier."], ["Substitute good", "This refers to the relationship between two different products.", "Look at the relationship between income and demand."], ["Complementary good", "This refers to goods used together.", "This is about income elasticity."]] },
    { id: 16109, chapter: 'Imperfect Competition', title: 'Monopoly Definition', prompt: 'Which of the following is a key characteristic of a pure monopoly?', correct: 'A single seller of a product with no close substitutes', wrong: [["Many sellers of identical products", "That describes perfect competition.", "Monopoly means 'one' seller."], ["Easy entry and exit", "Monopolies usually have high barriers to entry.", "If entry were easy, competition would drive out the monopoly."], ["Low prices for consumers", "Monopolies typically use their power to raise prices.", "They are price makers, not price takers."]] },
    { id: 16110, chapter: 'Elasticity', title: 'Price Elasticity', prompt: 'If a 10% increase in price leads to a 5% decrease in quantity demanded, the price elasticity of demand is:', correct: '0.5 (Inelastic)', wrong: [["2.0 (Elastic)", "You divided the price change by the quantity change.", "Elasticity is % change in quantity / % change in price."], ["1.0 (Unit Elastic)", "The changes are not equal in percentage.", "Check the ratio of 5 to 10."], ["5.0 (Elastic)", "You just used the quantity change percentage.", "You must divide by the price change."]] },
    { id: 16111, chapter: 'Supply and Demand', title: 'Tax Incidence', prompt: 'If demand is perfectly inelastic, who bears the entire burden of a sales tax?', correct: 'The consumers', wrong: [["The producers", "Inelastic demand means consumers will pay whatever price is asked.", "If consumers cannot reduce their quantity, they must pay the tax."], ["The government", "The government collects the tax; they don't pay it.", "Incidence is about who loses welfare."], ["It is split 50/50", "The burden split depends on relative elasticities.", "Perfectly inelastic demand is the extreme case."]] },
    { id: 16112, chapter: 'Production and Cost', title: 'MR=MC Rule', prompt: 'A firm should produce where MR = MC because this is the point where:', correct: 'Total profit is maximized', wrong: [["Total revenue is maximized", "Revenue is maximized when MR is zero, not when it equals MC.", "Profit is TR - TC."], ["Average cost is minimized", "ATC is minimized where MC = ATC, not necessarily where MR = MC.", "Efficiency and profit maximization are different."], ["Price is highest", "Producing more or less might allow a higher price but lower profit.", "Think about the last unit's contribution to profit."]] },
    { id: 16113, chapter: 'Imperfect Competition', title: 'Nash Equilibrium', prompt: 'In a 2x2 game, a Nash Equilibrium occurs when:', correct: 'Neither player can improve their payoff by changing only their own strategy', wrong: [["Both players get the highest possible total payoff", "That is the social optimum, which may not be a Nash equilibrium.", "Think about the 'best response' to the other player's move."], ["One player wins and the other loses", "Nash equilibria can exist in cooperative or win-win games.", "It is about the stability of the choices."], ["A player chooses a strategy that hurts the other player most", "That is a minimax strategy, not necessarily Nash.", "Nash is about mutual best responses."]] },
    { id: 16114, chapter: 'Factor Markets', title: 'MRP Hiring Rule', prompt: 'A firm should stop hiring workers when the wage is:', correct: 'Equal to the Marginal Revenue Product (MRP)', wrong: [["Equal to the product price", "You hire based on the value the worker adds, not just the price of one item.", "MRP = MP * P (in competition)."], ["Equal to the Average Product", "Hiring is a marginal decision.", "Always compare marginal benefit to marginal cost."], ["Zero", "You stop hiring long before the wage is zero.", "The wage is the cost of the worker."]] },
    { id: 16115, chapter: 'Supply and Demand', title: 'Price Ceilings', prompt: 'A binding price ceiling in a rental market causes deadweight loss primarily because:', correct: 'Mutually beneficial transactions are prevented', wrong: [["Landlords make too much profit", "A price ceiling usually reduces landlord profit.", "The problem is the reduction in quantity supplied."], ["The government has to pay for the housing", "The government doesn't pay; it just restricts the price.", "Market failure comes from the mismatch of S and D."], ["It encourages too much building", "Ceilings discourage building by lowering the return.", "Look at the shortage on the graph."]] },
    { id: 16116, chapter: 'Imperfect Competition', title: 'Excess Capacity', prompt: 'In the long run, a monopolistically competitive firm has "excess capacity" because:', correct: 'It produces at a point where ATC is still falling', wrong: [["It has empty warehouses", "Excess capacity is a technical term for the gap between current output and the min-ATC output.", "P = ATC at a point where MC < ATC."], ["It makes huge economic profits", "Economic profits are zero in the long run for these firms.", "The issue is the downward sloping demand curve."], ["It is more efficient than perfect competition", "It is less efficient because it doesn't produce at min ATC.", "It sacrifices efficiency for product variety."]] },
    { id: 16117, chapter: 'Imperfect Competition', title: 'Game Theory Strategies', prompt: 'In a repeated game, a "Tit-for-Tat" strategy is effective because it is:', correct: 'Clear, retaliatory, and forgiving', wrong: [["Completely unpredictable", "Unpredictability makes it hard for the other player to cooperate.", "Predictability helps sustain cooperation."], ["Aggressive and never cooperates", "That would lead to mutual defection forever.", "Forgiveness is key to restoring cooperation."], ["Based on complex calculus", "It's a very simple rule: do what the other player did last time.", "Simplicity is a strength."]] },
    { id: 16118, chapter: 'Market Failure', title: 'Externalities', prompt: 'With a negative externality, the market price is ____ and the market quantity is ____ compared to the social optimum.', correct: 'Too low; too high', wrong: [["Too high; too low", "Producers don't pay the external cost, so they supply too much at a low price.", "The social cost is higher than the private cost."], ["Correct; too high", "The price must reflect the social cost to be 'correct'.", "Price signals are distorted."], ["Too low; correct", "Distorted prices lead to distorted quantities.", "Both are wrong in a market failure."]] },
    { id: 16119, chapter: 'Market Failure', title: 'Asymmetric Information', prompt: 'The "Market for Lemons" theory explains why asymmetric information can lead to:', correct: 'Market collapse as high-quality goods are withdrawn', wrong: [["Lower prices for all cars", "Actually, it can cause the market for good cars to disappear entirely.", "Buyers won't pay for quality they can't verify."], ["Perfectly efficient outcomes", "Asymmetric information is a classic market failure.", "Information gaps block trades."], ["Government takeover of all used car sales", "While regulation is a response, the theory is about the market mechanism failing.", "High-quality sellers can't distinguish themselves."]] },
    { id: 16120, chapter: 'Factor Markets', title: 'Gini Coefficient', prompt: 'A Gini coefficient of 0.8 indicates:', correct: 'High income inequality', wrong: [["Perfect equality", "Perfect equality is 0.", "The closer to 1, the more unequal."], ["Moderate inequality", "0.8 is very high (most countries are between 0.2 and 0.6).", "Think of it as the area between the Lorenz curve and the line of equality."], ["High economic growth", "Gini measures distribution, not growth.", "A country can be rich or poor with high inequality."]] },
    { id: 16121, chapter: 'Basic Concepts', title: 'Comparative Advantage', prompt: 'If Country A can produce 10 Apples or 5 Bananas, and Country B can produce 6 Apples or 2 Bananas, who has the comparative advantage in Bananas?', correct: 'Country A', wrong: [["Country B", "Country B's cost for 1 Banana is 3 Apples. Country A's cost is 2 Apples.", "Lower opportunity cost wins."], ["Neither", "The costs are different (2 vs 3).", "Always compare the ratios."], ["Both", "Only one party can have the comparative advantage in a single good (unless costs are identical).", "It's a relative measure."]] },
    { id: 16122, chapter: 'Production and Cost', title: 'Shutdown Rule', prompt: 'In the long run, a firm should exit the market if:', correct: 'Price is less than Average Total Cost (ATC)', wrong: [["Price is less than Average Variable Cost (AVC)", "That is the short-run shutdown rule.", "In the long run, all costs are variable."], ["Economic profit is zero", "Zero economic profit is the 'normal' state in the long run.", "Firms stay as long as they cover opportunity costs."], ["Total revenue is falling", "Firms care about profit (TR-TC), not just the trend of revenue.", "If costs fall faster, they stay."]] },
    { id: 16123, chapter: 'Imperfect Competition', title: 'Price Discrimination', prompt: 'Perfect (first-degree) price discrimination results in:', correct: 'Zero consumer surplus and zero deadweight loss', wrong: [["Maximum consumer surplus", "Consumers pay exactly their maximum willingness to pay, leaving them with no surplus.", "The producer captures everything."], ["Maximum deadweight loss", "Actually, it is efficient because all mutually beneficial trades occur.", "Total surplus is maximized, but it's all producer surplus."], ["Lower total output", "Output is higher, matching the perfectly competitive level.", "The firm sells to every buyer willing to pay above MC."]] },
    { id: 16124, chapter: 'Market Failure', title: 'Coase Theorem', prompt: 'The Coase Theorem states that externalities can be solved privately if:', correct: 'Property rights are well-defined and transaction costs are low', wrong: [["The government sets a high tax", "The Coase Theorem is about avoiding government intervention through bargaining.", "It relies on private negotiation."], ["One party is much wealthier than the other", "Relative wealth doesn't matter for the efficiency of the outcome, only property rights.", "The initial allocation affects distribution, not efficiency."], ["All pollution is banned", "Banning pollution might not be the efficient outcome.", "Bargaining finds the optimal level of the externality."]] },
    { id: 16701, chapter: "Stretch Zone", title: "Game Theory: Nash Equilibrium", prompt: "In a Prisoner's Dilemma, what makes the dominant strategy equilibrium socially suboptimal?", correct: "Both players rationally choosing to defect leads to a Pareto-inferior outcome compared to mutual cooperation.", wrong: [["Players do not understand the rules.", "They do, but incentives lead them to defect.", "Rational self-interest leads to a worse collective outcome."], ["One player dominates the other.", "Both players have the same dominant strategy.", "Think Pareto efficiency."], ["It is actually a Pareto-optimal outcome.", "No, both could be better off if they cooperated.", "Cooperation is better but unstable."]] },
    { id: 16702, chapter: "Stretch Zone", title: "Market Failure: Externalities", prompt: "How does a Pigouvian tax correct a negative production externality?", correct: "It internalizes the external cost by making the firm's marginal private cost equal to the marginal social cost.", wrong: [["It subsidizes the affected third parties directly.", "A tax is levied on the producer.", "It forces the producer to feel the cost."], ["It bans the production of the good entirely.", "Taxes reduce quantity to the socially optimal level, not necessarily zero.", "Think 'internalize'."], ["It creates a positive externality instead.", "Taxes do not create positive externalities.", "It aligns private costs with social costs."]] },
    { id: 16703, chapter: "Stretch Zone", title: "Market Structure: Monopoly", prompt: "Why does a perfectly price-discriminating monopolist produce the same quantity as a perfectly competitive market?", correct: "They capture all consumer surplus, so there is no deadweight loss and marginal revenue exactly equals price for every unit.", wrong: [["They face a perfectly elastic demand curve.", "Monopolists face downward-sloping demand.", "They charge every consumer their exact willingness to pay."], ["They are regulated by the government.", "Perfect price discrimination is a theoretical behavior, not a regulation.", "MR = D in this specific case."], ["They have constant marginal costs.", "Cost structure doesn't cause this; the revenue structure does.", "Every new unit sold doesn't lower the price of previous units."]] },
    { id: 16704, chapter: "Stretch Zone", title: "Consumer Theory: Giffen Goods", prompt: "What uniquely characterizes a Giffen good?", correct: "The income effect dominates the substitution effect, leading to an upward-sloping demand curve.", wrong: [["The substitution effect dominates the income effect.", "That describes a normal good or an ordinary inferior good.", "Price goes up, demand goes up."], ["It is a luxury good with high status.", "That is a Veblen good.", "Giffen goods are extreme inferior goods, like staple foods in poverty."], ["Demand is perfectly inelastic.", "Inelastic demand is vertical; Giffen demand is upward-sloping.", "Price increases cause consumption to increase."]] },
    { id: 16705, chapter: "Stretch Zone", title: "Producer Theory: Economies of Scale", prompt: "Which of the following best explains why a natural monopoly exists?", correct: "The long-run average total cost curve is continuously declining over the relevant range of market demand.", wrong: [["The firm has an exclusive patent on a product.", "That is a legal monopoly.", "Think infrastructure like water pipes."], ["The firm owns all of a specific natural resource.", "That is resource monopoly.", "It's about economies of scale."], ["The government mandates that only one firm operates.", "That is a statutory monopoly.", "One firm can supply the market cheaper than two."]] },
    { id: 16706, chapter: "Stretch Zone", title: "Market Structure: Oligopoly", prompt: "In the Cournot model of duopoly, how do firms behave?", correct: "They simultaneously choose quantities, assuming the other firm's output is fixed.", wrong: [["They sequentially choose prices.", "That describes the Bertrand or Stackelberg models.", "Cournot is simultaneous quantity."], ["They collude to form a cartel.", "Cournot firms compete, they do not collude.", "They react to each other's expected output."], ["They simultaneously choose prices.", "That is the Bertrand model.", "Think quantity competition."]] },
    { id: 16707, chapter: "Stretch Zone", title: "Information Economics: Adverse Selection", prompt: "In the market for used cars ('lemons'), adverse selection occurs because:", correct: "Sellers have asymmetric information about quality, driving high-quality cars out of the market.", wrong: [["Buyers have asymmetric information about their willingness to pay.", "Sellers know the car's history, buyers don't.", "The information asymmetry favors the seller."], ["The government taxes used cars too heavily.", "This is a market failure due to information, not taxes.", "Good cars won't sell for the average price."], ["Sellers become reckless after selling the car.", "That is moral hazard.", "This happens before the transaction."]] },
    { id: 16708, chapter: "Stretch Zone", title: "Labor Economics: Monopsony", prompt: "A monopsonist in the labor market will hire workers up to the point where:", correct: "Marginal Revenue Product equals Marginal Factor Cost, resulting in lower wages than a competitive market.", wrong: [["Marginal Revenue equals Marginal Cost.", "That is for output markets, not factor markets.", "Look at the cost of hiring the next worker."], ["The wage equals the Marginal Revenue Product.", "That happens in a competitive labor market.", "A monopsonist must raise wages for all workers to hire one more."], ["The supply of labor is perfectly elastic.", "A monopsonist faces an upward-sloping labor supply curve.", "MFC > Wage."]] },
    { id: 16709, chapter: "Stretch Zone", title: "Consumer Theory: Indifference Curves", prompt: "Perfect complements have indifference curves shaped like:", correct: "Right angles (L-shaped).", wrong: [["Straight downward-sloping lines.", "Those are perfect substitutes.", "Think of left shoes and right shoes."], ["Upward-sloping curves.", "Indifference curves for goods are downward-sloping.", "More of one without the other adds no utility."], ["Circles.", "Those represent bliss points.", "L-shape indicates fixed proportions."]] },
    { id: 16710, chapter: "Stretch Zone", title: "General Equilibrium", prompt: "What is the core condition for Pareto efficiency in exchange?", correct: "The Marginal Rates of Substitution (MRS) must be equal for all consumers.", wrong: [["All consumers must have exactly equal wealth.", "Pareto efficiency does not imply equity.", "It means no mutually beneficial trades are left."], ["The Marginal Rate of Transformation must be zero.", "MRT relates to production, not exchange.", "Think of the Edgeworth box contract curve."], ["Prices must be zero.", "Prices align MRS, they are not zero.", "Consumers optimize to the same price ratio."]] },
  ]),
  macroeconomics: makeQuestionBank('University', [
    { id: 16201, chapter: 'Macroeconomics Dock', title: 'GDP idea', prompt: 'GDP measures:', correct: 'The value of final goods and services produced in an economy', wrong: [['Only stock prices', 'Stocks are not GDP by themselves.', 'GDP tracks production.'], ['Every country’s weather', 'Weather is not a national output measure.', 'Stay with goods and services.'], ['Only government salaries', 'GDP is much broader than one spending category.', 'Think economy-wide output.']] },
    { id: 16202, chapter: 'Macroeconomics Reef', title: 'Inflation', prompt: 'Inflation is:', correct: 'A general rise in prices over time', wrong: [['Any one expensive lunch', 'One price is not the same as general inflation.', 'The idea is economy-wide price level.'], ['A fall in unemployment only', 'That is a different macro variable.', 'Do not confuse different indicators.'], ['A rule that prices cannot change', 'Inflation is change, not a ban on change.', 'Focus on rising prices.']] },
    { id: 16203, chapter: 'Macroeconomics Cove', title: 'Fiscal policy', prompt: 'Fiscal policy usually refers to changes in:', correct: 'Government spending and taxation', wrong: [['Only rainfall and crop growth', 'That is agriculture, not policy.', 'Fiscal policy is budget-related.'], ['The speed of light', 'That is physics, not macroeconomics.', 'Use the government-budget definition.'], ['Private text messages', 'That is unrelated.', 'Think taxes and public spending.']] },
    { id: 16204, chapter: 'Macroeconomics Lagoon', title: 'Recession clue', prompt: 'A recession usually means:', correct: 'A period of economic decline', wrong: [['Every store closes forever', 'That is too extreme.', 'Recession is decline, not total collapse.'], ['Prices can never move again', 'That is not the definition.', 'The key is reduced economic activity.'], ['Only one company has trouble', 'Recession is economy-wide, not firm-specific.', 'Think broad slowdown.']] },
    { id: 16205, chapter: 'Economic Indicators', title: 'GDP Components', prompt: 'In the expenditure approach to GDP (Y = C + I + G + NX), what does "G" represent?', correct: 'Government spending on final goods and services', wrong: [["Transfer payments like Social Security", "Transfer payments are excluded from GDP because no new good or service is produced.", "Only government \"purchases\" count."], ["The total national debt", "Debt is a stock; GDP is a flow of annual production.", "G is annual spending."], ["Gold reserves", "Gold is an asset, not a component of annual production spending.", "Think of the government as a consumer of services and infrastructure."]] },
    { id: 16206, chapter: 'Economic Indicators', title: 'Unemployment Types', prompt: 'A worker who is in between jobs or just graduated is experiencing which type of unemployment?', correct: 'Frictional', wrong: [["Structural", "Structural unemployment is caused by a lack of matching skills or geographic mismatch.", "Frictional is temporary and part of a healthy job search."], ["Cyclical", "Cyclical unemployment is caused by a downturn in the business cycle.", "Graduating is a personal milestone, not a recession."], ["Permanent", "This isn't a standard category in macroeconomics.", "Most frictional unemployment is short-term."]] },
    { id: 16207, chapter: 'Economic Indicators', title: 'Inflation Definition', prompt: 'Inflation is best described as:', correct: 'A general increase in the overall price level over time', wrong: [["A rise in the price of one specific good, like gas", "Inflation must be \"general\" across the economy, not just one product.", "Use the CPI or GDP deflator as a guide."], ["A decrease in the purchasing power of money", "While true, this is a result of inflation, not the definition itself.", "Focus on the price level."], ["An increase in the total amount of money in the world", "Money supply growth can cause inflation, but it is not inflation itself.", "Distinguish between cause and effect."]] },
    { id: 16208, chapter: 'Basic Concepts', title: 'Business Cycle', prompt: 'The point in the business cycle where economic activity stops declining and begins to rise is the:', correct: 'Trough', wrong: [["Peak", "The peak is the highest point before a decline.", "Think of the bottom of the valley."], ["Expansion", "Expansion is the period of growth, not the turning point itself.", "The turning point at the bottom is the trough."], ["Recession", "A recession is the period of decline.", "The trough is the end of the recession."]] },
    { id: 16209, chapter: 'Basic Concepts', title: 'Circular Flow', prompt: 'In the circular flow model, which of the following is an "injection" into the economy?', correct: 'Investment (I)', wrong: [["Savings (S)", "Savings is a \"leakage\" because it pulls money out of the current spending stream.", "Injections add to the stream."], ["Taxes (T)", "Taxes are a leakage because they reduce private spending power.", "Government spending (G) is the injection."], ["Imports (M)", "Imports are a leakage because money leaves the domestic economy.", "Exports (X) are the injection."]] },
    { id: 16210, chapter: 'Economic Indicators', title: 'Real vs Nominal GDP', prompt: 'If nominal GDP rose by 10% and the price level (deflator) rose by 4%, what was the approximate growth in real GDP?', correct: '6%', wrong: [["14%", "You added the percentages instead of subtracting the inflation.", "Real growth = Nominal growth - Inflation."], ["10%", "You ignored the price level change.", "Nominal GDP must be adjusted for inflation to find real growth."], ["2.5%", "You divided 10 by 4.", "Use the additive approximation for small percentages."]] },
    { id: 16211, chapter: 'AD/AS', title: 'The Multiplier', prompt: 'If the Marginal Propensity to Consume (MPC) is 0.8, what is the spending multiplier?', correct: '5', wrong: [["0.2", "That is the Marginal Propensity to Save (MPS).", "Multiplier = 1 / (1 - MPC)."], ["1.25", "You divided 1 by 0.8.", "The formula is 1 / MPS."], ["10", "That would be an MPC of 0.9.", "Calculate 1 / 0.2."]] },
    { id: 16212, chapter: 'Financial Sector', title: 'Money Market', prompt: 'If the central bank increases the money supply, what is the immediate effect on the nominal interest rate?', correct: 'It falls', wrong: [["It rises", "An increase in supply, with constant demand, lowers the \"price\" (interest rate).", "Think of the MD/MS graph."], ["It stays the same", "The money market reaches a new equilibrium at a different rate.", "Interest rates are determined by supply and demand."], ["It becomes unpredictable", "The model predicts a clear downward pressure on rates.", "More money available makes it cheaper to borrow."]] },
    { id: 16213, chapter: 'Open Economy', title: 'Comparative Advantage', prompt: 'A country has a comparative advantage in a good if it can produce that good:', correct: 'At a lower opportunity cost than its trading partner', wrong: [["Using fewer total resources than any other country", "That is absolute advantage.", "Comparative advantage is about relative costs."], ["At the highest possible price", "Comparative advantage is about efficiency and cost, not price skimming.", "Lower cost allows for better terms of trade."], ["Only if it has no other goods to produce", "Every country has a comparative advantage in something.", "It's about where they are \"least bad\" or \"most good\"."]] },
    { id: 16214, chapter: 'AD/AS', title: 'Fiscal Policy', prompt: 'Which of the following is an example of discretionary fiscal policy?', correct: 'A law passed to increase infrastructure spending', wrong: [["A rise in unemployment benefits paid during a recession", "This is an \"automatic stabilizer\" that happens without new laws.", "Discretionary policy requires specific legislative action."], ["The Fed lowering interest rates", "That is monetary policy, not fiscal policy.", "Fiscal policy is set by the government (G and T)."], ["A decrease in tax revenue because people earned less", "This is an automatic stabilizer.", "Think \"active\" vs \"passive\" changes."]] },
    { id: 16215, chapter: 'Stabilization Policies', title: 'SRPC Shift', prompt: 'Stagflation (simultaneous high inflation and high unemployment) is represented on the Phillips Curve as:', correct: 'A rightward shift of the Short-Run Phillips Curve (SRPC)', wrong: [["A movement along the SRPC", "Movement along the curve shows the tradeoff, not both rising together.", "Shifts occur when expectations or supply change."], ["A leftward shift of the Long-Run Phillips Curve", "The LRPC is vertical at the natural rate and doesn't shift for stagflation.", "Stagflation is a short-run supply shock."], ["A shift to the origin", "That would mean zero inflation and zero unemployment.", "Think of the 1970s oil shocks."]] },
    { id: 16216, chapter: 'AD/AS', title: 'Crowding Out', prompt: 'In the loanable funds market, an increase in the government deficit "crowds out" private investment because:', correct: 'The real interest rate rises', wrong: [["The government bans private borrowing", "The government just competes for funds, it doesn't ban others.", "Higher demand for funds raises the interest rate."], ["People stop saving money", "Actually, higher rates might encourage more saving, but not enough to offset the deficit.", "The key is the cost of borrowing for firms."], ["Taxes are lowered too much", "Lower taxes might cause the deficit, but the \"crowding out\" happens through the interest rate.", "Trace the effect from deficit to D_lf to interest rate."]] },
    { id: 16217, chapter: 'Financial Sector', title: 'Money Multiplier', prompt: 'If the reserve requirement is 10%, but banks choose to hold 5% in excess reserves and customers keep 5% of their money as cash leakages, the actual money multiplier will be:', correct: '5', wrong: [["10", "That is the simple multiplier (1/0.1).", "Leakages and excess reserves reduce the multiplier."], ["20", "That would be a 5% total reserve ratio with no leakages.", "The denominator is (reserve ratio + excess reserves + leakage ratio)."], ["2", "That would be a 50% total ratio.", "0.1 + 0.05 + 0.05 = 0.2. 1/0.2 = 5."]] },
    { id: 16218, chapter: 'Open Economy', title: 'Exchange Rates', prompt: 'If the real interest rate in the US rises relative to the Eurozone, the US Dollar will likely ____ because ____.', correct: 'Appreciate; foreign investors demand more dollars to buy US assets', wrong: [["Depreciate; US citizens want to buy more European goods", "Higher interest rates attract capital, which strengthens the currency.", "Follow the flow of money toward higher returns."], ["Appreciate; the US will export more goods", "Higher rates might actually hurt exports by making them more expensive.", "The primary short-run driver is capital flows."], ["Depreciate; there is more money in circulation", "Rising rates are usually linked to tighter money supply.", "Think of the Demand for Dollars shifting right."]] },
    { id: 16219, chapter: 'Open Economy', title: 'BoP Identity', prompt: 'If a country has a current account deficit, it MUST have:', correct: 'A financial account surplus', wrong: [["A government budget surplus", "The \"twin deficits\" can happen, but they aren't an identity.", "BoP must balance: CA + FA = 0."], ["High inflation", "BoP balance is a recording identity, not a price level driver.", "Capital must flow in to pay for the trade deficit."], ["No exports", "A deficit just means imports exceed exports.", "It is about the net flow."]] },
    { id: 16220, chapter: 'Open Economy', title: 'The Trilemma', prompt: 'According to the "Trilemma" of international macro, a country can only choose TWO of the following. Which one is NOT part of the trilemma?', correct: 'Low inflation', wrong: [["A fixed exchange rate", "This is one of the three goals.", "Choose between stability, autonomy, and openness."], ["Free capital movement", "This is the second goal.", "Countries often sacrifice this to keep control."], ["Independent monetary policy", "This is the third goal.", "You can't have all three simultaneously."]] },
    { id: 16221, chapter: 'Financial Sector', title: 'Quantity Theory', prompt: 'In the Quantity Theory of Money (MV = PY), if Velocity (V) and Real Output (Y) are constant, a 5% increase in the Money Supply (M) will lead to:', correct: 'A 5% increase in the Price Level (P)', wrong: [["A 5% decrease in prices", "More money chasing the same goods raises prices.", "MV = PY implies proportionality in the long run."], ["No change in prices", "This contradicts the basic quantity theory.", "Money is \"neutral\" and only affects nominal variables."], ["A 5% increase in real GDP", "The theory assumes Y is determined by resources, not money.", "Distinguish between nominal and real GDP."]] },
    { id: 16222, chapter: 'Stabilization Policies', title: 'Solow Growth', prompt: 'In the Solow growth model, the only source of long-run sustained increase in Real GDP per capita is:', correct: 'Technological progress', wrong: [["An increase in the savings rate", "Savings only increases the level of capital, leading to a one-time growth burst until a new steady state.", "Diminishing returns to capital limit its long-run impact."], ["Population growth", "Population growth increases total GDP but not necessarily GDP per capita.", "In fact, it can reduce capital per worker."], ["Discovery of more land", "Land is a finite resource and subject to diminishing returns.", "Only \"ideas\" (technology) can keep pushing output higher."]] },
    { id: 16223, chapter: 'Stabilization Policies', title: 'Ricardian Equivalence', prompt: 'Ricardian Equivalence suggests that a tax cut funded by government debt will have no effect on Aggregate Demand because:', correct: 'Consumers save the tax cut to pay for future tax increases', wrong: [["The government will spend it all anyway", "The theory is about how private consumers react.", "They see the future debt burden."], ["Interest rates will fall", "Deficit spending usually raises interest rates.", "Debt is a promise of future taxes."], ["The multiplier is always zero", "It's not that the multiplier is zero, but that the initial stimulus is offset by saving.", "Think \"forward-looking\" consumers."]] },
    { id: 16224, chapter: 'Financial Sector', title: 'Modern Tools', prompt: 'In a modern "abundant reserves" framework, the Fed primarily controls the federal funds rate by adjusting:', correct: 'Interest on Reserve Balances (IORB)', wrong: [["Open market operations", "While still used, OMOs are no longer the primary \"daily\" tool for hitting the target.", "The Fed sets a \"floor\" for rates."], ["Reserve requirements", "The Fed effectively eliminated reserve requirements in 2020.", "It is no longer a tool for steering rates."], ["Printing physical cash", "Cash is a small part of the money supply and not a policy tool.", "Think of the electronic rate paid to banks."]] },
    { id: 16801, chapter: "Stretch Zone", title: "Monetary Policy: Taylor Rule", prompt: "The Taylor Rule suggests central banks should set the nominal interest rate based on:", correct: "The deviation of inflation from its target and the output gap.", wrong: [["The price of gold and the stock market index.", "The Taylor rule focuses on macroeconomic stability.", "Inflation and GDP are the key inputs."], ["The money supply growth rate only.", "That is monetarism (Friedman's k-percent rule).", "It responds to current economic conditions."], ["The national debt and the budget deficit.", "Those are fiscal policy concerns.", "It guides monetary policy."]] },
    { id: 16802, chapter: "Stretch Zone", title: "Fiscal Policy: Crowding Out", prompt: "What is the primary mechanism of the crowding-out effect?", correct: "Government borrowing increases the real interest rate, which reduces private investment.", wrong: [["Government spending directly replaces private consumption.", "It operates through financial markets.", "Deficits lead to borrowing."], ["Taxes decrease, leaving consumers with more money.", "That would be crowding in or just expansionary.", "Think about the loanable funds market."], ["The central bank prints too much money.", "That causes inflation, not crowding out.", "Interest rates rise."]] },
    { id: 16803, chapter: "Stretch Zone", title: "Economic Growth: Solow Model", prompt: "In the Solow growth model, steady-state long-run per capita growth is driven exclusively by:", correct: "Exogenous technological progress.", wrong: [["Increases in the savings rate.", "Higher savings increase the steady-state level of income, but not the long-run growth rate.", "Diminishing returns to capital stop growth eventually."], ["Population growth.", "Higher population growth actually decreases steady-state capital per worker.", "You need something that makes labor more effective."], ["Capital accumulation.", "Capital runs into diminishing marginal returns.", "Technology (A) is the engine of growth."]] },
    { id: 16804, chapter: "Stretch Zone", title: "Open Economy: Mundell-Fleming Model", prompt: "In a small open economy with perfect capital mobility and floating exchange rates, expansionary fiscal policy will:", correct: "Cause the currency to appreciate, crowding out net exports entirely and leaving income unchanged.", wrong: [["Increase income significantly due to the multiplier effect.", "That happens in a closed economy or with fixed exchange rates.", "The exchange rate absorbs the shock."], ["Cause the currency to depreciate, boosting net exports.", "Higher interest rates attract capital, causing appreciation.", "Capital inflows strengthen the currency."], ["Decrease the domestic interest rate.", "Fiscal expansion puts upward pressure on rates.", "Capital mobility keeps rates at the world level."]] },
    { id: 16805, chapter: "Stretch Zone", title: "Inflation: Phillips Curve", prompt: "The long-run Phillips curve is vertical at the natural rate of unemployment because:", correct: "In the long run, inflation expectations fully adjust to actual inflation.", wrong: [["Wages are perfectly sticky in the long run.", "Wages are flexible in the long run.", "People cannot be continually fooled."], ["The government controls the unemployment rate.", "Unemployment is determined by real factors (frictions, structure).", "Monetary policy cannot affect real variables in the long run."], ["Inflation is always zero in the long run.", "Inflation can be anything, but unemployment returns to the natural rate.", "Money is neutral in the long run."]] },
    { id: 16806, chapter: "Stretch Zone", title: "Central Banking: Quantitative Easing", prompt: "How does Quantitative Easing primarily differ from traditional open market operations?", correct: "It involves purchasing long-term securities to lower long-term interest rates when short-term rates are already at zero.", wrong: [["It only involves selling bonds.", "QE is large-scale purchasing.", "It's used when the zero lower bound is reached."], ["It targets the overnight lending rate.", "Traditional OMO targets the overnight rate.", "QE targets the yield curve further out."], ["It is conducted by the Treasury, not the Central Bank.", "The Central Bank conducts QE.", "It expands the central bank's balance sheet massively."]] },
    { id: 16807, chapter: "Stretch Zone", title: "Theories: Real Business Cycle", prompt: "Real Business Cycle (RBC) theory attributes macroeconomic fluctuations primarily to:", correct: "Real exogenous shocks to productivity and technology.", wrong: [["Failures in aggregate demand.", "That is Keynesian theory.", "RBC focuses on aggregate supply."], ["Erratic monetary policy.", "That is Monetarist theory.", "RBC assumes money is neutral even in the short run."], ["Irrational exuberance of investors.", "RBC models assume perfect rationality and efficient markets.", "Think 'technology shocks'."]] },
    { id: 16808, chapter: "Stretch Zone", title: "Exchange Rates: Purchasing Power Parity", prompt: "Absolute Purchasing Power Parity implies that:", correct: "The real exchange rate is constant and equal to one.", wrong: [["Nominal exchange rates never change.", "Nominal rates adjust to inflation differentials.", "A basket of goods costs the same everywhere."], ["All countries must use the same currency.", "PPP applies across different currencies.", "It relies on the Law of One Price."], ["Interest rates are equal across countries.", "That is Interest Rate Parity.", "This is about goods, not financial assets."]] },
    { id: 16809, chapter: "Stretch Zone", title: "Banking: Money Multiplier", prompt: "If the public holds a higher proportion of their money as cash rather than deposits, the money multiplier will:", correct: "Decrease.", wrong: [["Increase.", "Cash drains reduce the banking system's ability to create loans.", "Banks have fewer reserves to lend."], ["Stay the same.", "The currency-deposit ratio is a key component of the multiplier.", "More cash means less money creation."], ["Become negative.", "The multiplier is always positive.", "It just gets smaller."]] },
    { id: 16810, chapter: "Stretch Zone", title: "Ricardian Equivalence", prompt: "Ricardian equivalence argues that a debt-financed tax cut has no effect on aggregate demand because:", correct: "Consumers will save the entirety of the tax cut to pay for expected future tax increases.", wrong: [["The government will default on the debt.", "It assumes the government will eventually pay it off via taxes.", "Consumers are forward-looking."], ["Consumers will spend all of it immediately.", "That is the traditional Keynesian view.", "They realize their lifetime wealth hasn't changed."], ["The central bank will offset it with higher interest rates.", "That is monetary offset.", "This is a purely fiscal behavioral theory."]] },
  ]),
  organicChemistry: makeQuestionBank('University', [
    { id: 16301, chapter: 'Organic Chemistry Dock', title: 'Carbon fact', prompt: 'Organic chemistry is mainly centered on compounds containing:', correct: 'Carbon', wrong: [['Only iron', 'Iron is not the central atom of organic chemistry.', 'Organic chemistry revolves around carbon compounds.'], ['Only gold', 'Gold is unrelated to the core definition.', 'Choose the atom that forms organic backbones.'], ['Only helium', 'Helium is inert and not central here.', 'Carbon is the key clue.']] },
    { id: 16302, chapter: 'Organic Chemistry Reef', title: 'Hydrocarbon', prompt: 'A hydrocarbon contains only:', correct: 'Hydrogen and carbon', wrong: [['Hydrogen and oxygen only', 'That would exclude carbon.', 'Hydrocarbons are carbon-hydrogen compounds.'], ['Carbon and sodium', 'Sodium is not part of the definition.', 'Use the word parts hydro and carbon.'], ['Any three random elements', 'The definition is specific.', 'Stick to hydrogen and carbon.']] },
    { id: 16303, chapter: 'Organic Chemistry Cove', title: 'Functional group role', prompt: 'A functional group mainly helps identify:', correct: 'A characteristic pattern of reactivity', wrong: [['The classroom number', 'That is unrelated.', 'Functional groups predict behavior.'], ['The exact color of the liquid only', 'Appearance can vary and is not the main point.', 'Reactivity is the important clue.'], ['Only the molecule’s boiling kettle', 'That is nonsense here.', 'Think reaction patterns.']] },
    { id: 16304, chapter: 'Organic Chemistry Lagoon', title: 'Isomer idea', prompt: 'Isomers are compounds that share:', correct: 'The same molecular formula but different arrangements', wrong: [['Different formulas and identical structure', 'That is the opposite of isomerism.', 'Same formula, different arrangement is the classic definition.'], ['No atoms in common', 'They share the same formula.', 'Do not lose the shared composition idea.'], ['Only the same smell', 'Smell is not the defining feature.', 'Use formula plus arrangement.']] },
    { id: 16305, chapter: 'Structure and Bonding', title: 'Carbon Hybridization', prompt: 'What is the hybridization of the carbon atom in methane (CH4)?', correct: 'sp3', wrong: [["sp2", "sp2 hybridization is for carbons with one double bond, like in ethene.", "Methane has four single bonds."], ["sp", "sp hybridization is for carbons with a triple bond or two double bonds.", "Methane's geometry is tetrahedral."], ["p3", "Hybridization involves 's' and 'p' orbitals mixing.", "Think of the four equivalent C-H bonds."]] },
    { id: 16306, chapter: 'Alkanes and Stereochemistry', title: 'IUPAC Nomenclature', prompt: 'What is the IUPAC name for a straight-chain alkane with 5 carbon atoms?', correct: 'Pentane', wrong: [["Butane", "Butane has 4 carbons.", "Prefixes: meth, eth, but, pent..."], ["Hexane", "Hexane has 6 carbons.", "Count the carbon backbone."], ["Propane", "Propane has 3 carbons.", "Use the standard prefix for five."]] },
    { id: 16307, chapter: 'Alkanes and Stereochemistry', title: 'Chirality', prompt: 'A molecule that is not superimposable on its mirror image is called:', correct: 'Chiral', wrong: [["Achiral", "Achiral molecules are identical to their mirror images.", "Chiral comes from the Greek word for hand."], ["Meso", "Meso compounds have chiral centers but are achiral due to internal symmetry.", "This is a broader definition."], ["Isotopic", "Isotopes are atoms with different neutron counts, not a mirror-image property.", "Think of hands (left vs right)."]]},
    { id: 16308, chapter: 'Spectroscopy', title: 'IR Spectroscopy', prompt: 'In an IR spectrum, a broad peak around 3300 cm⁻¹ typically indicates which functional group?', correct: 'Alcohol (OH)', wrong: [["Carbonyl (C=O)", "Carbonyl peaks are sharp and usually around 1700 cm⁻¹.", "Hydrogen bonding makes OH peaks broad."], ["Alkane (C-H)", "C-H stretches are usually just below 3000 cm⁻¹.", "OH is further to the left and much broader."], ["Alkyne (C≡C)", "Triple bonds are usually in the 2100-2200 cm⁻¹ range.", "3300 is the region for O-H or N-H."]] },
    { id: 16309, chapter: 'Substitution and Elimination', title: 'Carbocation Stability', prompt: 'Which of the following carbocations is the most stable?', correct: 'Tertiary (3°)', wrong: [["Primary (1°)", "Primary carbocations have less inductive stabilization and hyperconjugation.", "More alkyl groups help spread out the positive charge."], ["Secondary (2°)", "Secondary is more stable than primary but less than tertiary.", "The more neighbors, the better."], ["Methyl", "A methyl carbocation is the least stable.", "Inductive effects from attached carbons are key."]] },
    { id: 16310, chapter: 'Alkanes and Stereochemistry', title: 'R/S Configuration', prompt: 'When assigning R/S configuration, what is the first step in the Cahn-Ingold-Prelog (CIP) priority rules?', correct: 'Compare the atomic numbers of the atoms directly attached to the chiral center', wrong: [["Compare the total molecular weight of the groups", "Priority is based on atomic number of the first atom, not total mass.", "Higher atomic number gets higher priority."], ["Count the number of hydrogens in each group", "Hydrogen always has the lowest priority (atomic number 1).", "Start at the first point of difference."], ["Check the color of the molecule", "Atomic properties, not physical appearance, determine priority.", "Use the periodic table."]] },
    { id: 16311, chapter: 'Alkanes and Stereochemistry', title: 'Newman Projections', prompt: 'Which conformation of butane is the lowest in energy (most stable)?', correct: 'Anti-staggered', wrong: [["Gauche-staggered", "Gauche has steric strain from bulky groups being 60 degrees apart.", "Anti has them 180 degrees apart."], ["Eclipsed", "Eclipsed conformations have both torsional and steric strain.", "Always less stable than staggered."], ["Totally eclipsed", "This is the highest energy state where the largest groups overlap.", "Maximize the distance between large groups."]] },
    { id: 16312, chapter: 'Substitution and Elimination', title: 'SN2 Characteristics', prompt: 'An SN2 reaction typically results in what stereochemical outcome at the chiral center?', correct: 'Inversion of configuration (Walden inversion)', wrong: [["Racemization", "Racemization (a mix of R and S) is characteristic of SN1 reactions.", "SN2 is concerted and attacks from the backside."], ["Retention of configuration", "The nucleophile replaces the leaving group from the opposite side.", "Configuration is flipped."], ["Formation of a meso compound", "This depends on the whole molecule, but the specific center always inverts.", "Backside attack is the key mechanism."]] },
    { id: 16313, chapter: 'Substitution and Elimination', title: 'Zaitsev\'s Rule', prompt: 'According to Zaitsev\'s rule, the major product of an E2 elimination is usually:', correct: 'The more substituted alkene', wrong: [["The less substituted alkene", "That is the Hofmann product, usually formed with bulky bases.", "Substitution increases alkene stability."], ["The most acidic alkane", "Elimination forms an alkene, not an alkane.", "Think about double bond stability."], ["The product with the most hydrogens", "More substitution means fewer hydrogens on the double bond carbons.", "Stable double bonds have more carbon neighbors."]] },
    { id: 16314, chapter: 'Spectroscopy', title: 'NMR Multiplicity', prompt: 'According to the n+1 rule in ¹H NMR, a proton with 3 equivalent neighboring protons will appear as a:', correct: 'Quartet', wrong: [["Triplet", "A triplet comes from 2 neighbors.", "3 neighbors + 1 = 4."], ["Singlet", "A singlet has no neighbors.", "Check the adjacent carbons."], ["Doublet", "A doublet comes from 1 neighbor.", "Use the n+1 formula."]] },
    { id: 16315, chapter: 'Substitution and Elimination', title: 'Competition (SN1/SN2/E1/E2)', prompt: 'A secondary alkyl halide reacted with a strong, bulky base (like t-BuOK) in a polar aprotic solvent will primarily undergo:', correct: 'E2', wrong: [["SN2", "Strong bulky bases are poor nucleophiles due to steric hindrance, favoring elimination over substitution.", "Secondary substrates are sensitive to base bulk."], ["SN1", "Strong bases favor concerted (bimolecular) pathways.", "SN1 needs a weak nucleophile and stable carbocation."], ["E1", "E1 occurs with weak bases and usually tertiary substrates.", "Strong bases drive the E2 mechanism."]] },
    { id: 16316, chapter: 'Alkanes and Stereochemistry', title: 'Chair Conformations', prompt: 'In the most stable chair conformation of cis-1,2-dimethylcyclohexane:', correct: 'One methyl group is axial and one is equatorial', wrong: [["Both methyl groups are equatorial", "In a 1,2-cis relationship, one must be up and one must be down relative to the plane; on a chair, this means ax/eq or eq/ax.", "Check the geometry of the 1,2 positions."], ["Both methyl groups are axial", "This would be the least stable conformation due to 1,3-diaxial interactions.", "One equatorial is better than none."], ["The ring becomes planar", "Cyclohexane rings are not planar because it would cause significant angle and torsional strain.", "The chair minimizes energy."]] },
    { id: 16317, chapter: 'Structure and Bonding', title: 'Resonance Stability', prompt: 'Which resonance structure is generally considered the most stable (major contributor)?', correct: 'The one with the most atoms having a complete octet', wrong: [["The one with the most formal charges", "Stability is usually higher when formal charges are minimized.", "Octets are more important than charge minimization."], ["The one with a positive charge on oxygen", "Oxygen is highly electronegative and 'prefers' a negative charge unless it has a full octet.", "Check the electronegativities."], ["The one with the fewest double bonds", "More covalent bonds usually increase stability.", "Full octets and more bonds are better."]] },
    { id: 16318, chapter: 'Reactions of Alkenes', title: 'Hydroboration-Oxidation', prompt: 'The hydroboration-oxidation of 1-methylcyclopentene yields which major product?', correct: 'trans-2-methylcyclopentanol (anti-Markovnikov, syn-addition)', wrong: [["1-methylcyclopentanol", "That would be a Markovnikov addition (OH on the more substituted carbon).", "BH3 adds to the less substituted side."], ["cis-2-methylcyclopentanol", "The addition of H and BH2 is syn, but the resulting OH and Methyl end up trans.", "Analyze the syn-addition geometry."], ["2-methylcyclopentanone", "Oxidation of the borane intermediate yields an alcohol, not a ketone.", "The OH is on the less substituted carbon."]] },
    { id: 16319, chapter: 'Reactions of Alkenes', title: 'Synthesis Strategy', prompt: 'To convert 1-bromobutane into 1-butyne, which sequence of reagents is most effective?', correct: '1. t-BuOK; 2. Br2; 3. Excess NaNH2', wrong: [["1. NaOH; 2. H2SO4; 3. Heat", "NaOH would give an alcohol, not an alkyne.", "You need to form a double bond first, then a dihalide."], ["1. NaNH2; 2. H2", "NaNH2 is a base, but it won't form an alkyne from an alkane in one step.", "Alkyne synthesis usually goes through a dihalide elimination."], ["1. HBr; 2. Mg/Ether", "This would make a Grignard reagent, not an alkyne.", "Think elimination and dihalogenation."]] },
    { id: 16320, chapter: 'Spectroscopy', title: 'Structure Elucidation', prompt: 'A compound with formula C4H8O has a strong IR peak at 1715 cm⁻¹ and a singlet at 2.1 ppm (3H) in ¹H NMR. It is likely:', correct: '2-butanone', wrong: [["Butanal", "Aldehydes have a distinct C-H peak in IR around 2700-2800 cm⁻¹ and an NMR signal at 9-10 ppm.", "The singlet at 2.1 is characteristic of a methyl ketone."], ["Cyclobutanol", "Alcohols have an OH peak around 3300 cm⁻¹, and there is no carbonyl peak at 1715.", "The IR says ketone or aldehyde."], ["Tetrahydrofuran (THF)", "Ethers lack a carbonyl peak at 1715 cm⁻¹.", "Look for the C=O stretch."]] },
    { id: 16321, chapter: 'Reactions of Alkenes', title: 'E/Z Nomenclature', prompt: 'In (E)-3-methyl-2-pentene, where are the higher-priority groups located relative to the double bond?', correct: 'On opposite sides (trans-like)', wrong: [["On the same side (cis-like)", "That would be the (Z) isomer (Zusammen = together).", "(E) comes from Entgegen (opposite)."], ["Attached to the same carbon", "Groups are prioritized on each end of the double bond.", "Compare the two groups on C2 and the two on C3."], ["In the same plane", "Double bonds are always planar; the nomenclature describes the orientation in that plane.", "Use the CIP rules for each carbon."]] },
    { id: 16322, chapter: 'Stretch Zone', title: 'Diels-Alder Stereochemistry', prompt: 'The Diels-Alder reaction of 1,3-butadiene and maleic anhydride typically favors the "endo" product because of:', correct: 'Secondary orbital interactions in the transition state', wrong: [["Steric hindrance being minimized", "Actually, the endo product is often more sterically crowded.", "The electronic effect dominates in the transition state."], ["The reaction being reversible", "Most Diels-Alder reactions are kinetically controlled to give the endo product.", "Endo is the faster-forming product."], ["The use of a catalyst", "The endo rule applies even to uncatalyzed thermal reactions.", "It's an intrinsic orbital property."]] },
    { id: 16323, chapter: 'Structure and Bonding', title: 'pKa Prediction', prompt: 'Which of the following has the lowest pKa (is the strongest acid)?', correct: 'Trichloroacetic acid (Cl3CCOOH)', wrong: [["Acetic acid (CH3COOH)", "Chlorine atoms are electron-withdrawing and stabilize the conjugate base via induction.", "Induction increases acidity."], ["Ethanol (CH3CH2OH)", "Alcohols are much weaker acids than carboxylic acids.", "Compare the stability of the conjugate bases."], ["Trifluoroethanol (CF3CH2OH)", "While more acidic than ethanol, it is still less acidic than trichloroacetic acid because the carboxyl group stabilizes the charge by resonance.", "Resonance usually beats induction."]] },
    { id: 16324, chapter: 'Reactions of Alkenes', title: 'Epoxidation', prompt: 'The reaction of trans-2-butene with mCPBA (meta-chloroperoxybenzoic acid) yields:', correct: 'trans-2,3-dimethyloxirane (a racemic mixture)', wrong: [["cis-2,3-dimethyloxirane (a meso compound)", "Epoxidation is a syn-addition; the stereochemistry of the alkene is preserved.", "Trans alkene stays trans in the ring."], ["Butane-2,3-diol", "mCPBA forms an epoxide, not a diol.", "Acidic workup of the epoxide would give the diol."], ["2-butanone", "This is an addition reaction, not a rearrangement to a ketone.", "The double bond is converted to a three-membered ring."]] },
    { id: 16901, chapter: "Stretch Zone", title: "Stereochemistry: Chirality", prompt: "A molecule with two chiral centers that is superimposable on its mirror image is called:", correct: "A meso compound.", wrong: [["An enantiomer.", "Enantiomers are non-superimposable mirror images.", "It has a plane of symmetry."], ["A diastereomer.", "Diastereomers are non-mirror image stereoisomers.", "Meso compounds are achiral."], ["A racemic mixture.", "A racemic mixture is a 50/50 mix of two enantiomers.", "This is a single achiral molecule."]] },
    { id: 16902, chapter: "Stretch Zone", title: "Mechanisms: SN2", prompt: "The rate of an SN2 reaction is heavily dependent on:", correct: "Steric hindrance at the electrophilic carbon and the concentration of the nucleophile.", wrong: [["Carbocation stability.", "SN2 does not form a carbocation intermediate; SN1 does.", "It is a concerted, one-step mechanism."], ["The concentration of the electrophile only.", "It is a bimolecular reaction, so both concentrations matter.", "Rate = k[E][Nu]."], ["The use of a protic solvent.", "Protic solvents slow down SN2 reactions by solvating the nucleophile.", "Sterics dictate the backside attack."]] },
    { id: 16903, chapter: "Stretch Zone", title: "Mechanisms: E2", prompt: "For an E2 elimination to occur on a cyclohexane ring, the leaving group and the beta-hydrogen must be:", correct: "Anti-periplanar and both in axial positions.", wrong: [["Syn-periplanar and both in equatorial positions.", "They must be 180 degrees apart.", "Equatorial positions cannot be anti-periplanar to each other."], ["Gauche to each other.", "That is a 60-degree angle, unsuitable for the concerted mechanism.", "Think trans-diaxial."], ["Both attached to the same carbon.", "Elimination requires a beta-hydrogen on an adjacent carbon.", "The double bond forms between alpha and beta carbons."]] },
    { id: 16904, chapter: "Stretch Zone", title: "Aromaticity: Huckel's Rule", prompt: "For a compound to be aromatic, it must be cyclic, planar, fully conjugated, and have how many pi electrons?", correct: "4n + 2", wrong: [["4n", "That is the rule for antiaromatic compounds.", "Think of benzene, which has 6 pi electrons (n=1)."], ["2n", "That is not a rule in aromaticity.", "The formula requires + 2."], ["An odd number.", "Pi electrons come in pairs.", "Benzene has 6, naphthalene has 10."]] },
    { id: 16905, chapter: "Stretch Zone", title: "Spectroscopy: NMR", prompt: "In H-NMR spectroscopy, a signal split into a quartet indicates that the proton is adjacent to:", correct: "Three equivalent neighboring protons.", wrong: [["Four equivalent neighboring protons.", "The n+1 rule dictates the splitting pattern.", "n neighbors give n+1 peaks."], ["Two equivalent neighboring protons.", "Two neighbors would produce a triplet.", "n+1 = 4, so n = 3."], ["An electronegative atom like oxygen.", "That affects chemical shift (deshielding), not splitting.", "Look at adjacent carbons."]] },
    { id: 16906, chapter: "Stretch Zone", title: "Reactions: Diels-Alder", prompt: "The Diels-Alder reaction is best described as:", correct: "A [4+2] concerted cycloaddition between a diene and a dienophile.", wrong: [["A step-wise radical substitution.", "It is concerted and pericyclic.", "There are no intermediates."], ["A nucleophilic acyl substitution.", "It forms a cyclic system, usually a cyclohexene ring.", "It involves pi electrons reacting in a ring."], ["An electrophilic aromatic substitution.", "It does not require an aromatic ring.", "It forms a six-membered ring."]] },
    { id: 16907, chapter: "Stretch Zone", title: "Carbonyl Chemistry: Aldol Condensation", prompt: "The driving force for the dehydration step in an aldol condensation is:", correct: "The formation of a highly stable conjugated alpha, beta-unsaturated carbonyl system.", wrong: [["The formation of a carbocation.", "Dehydration usually proceeds via an E1cB mechanism under basic conditions.", "Conjugation lowers the overall energy."], ["The release of a molecule of hydrogen gas.", "Water is released, not hydrogen gas.", "Look at the double bond placement."], ["Steric strain relief.", "The product is more stable due to electronics (conjugation), not just sterics.", "Pi bonds align."]] },
    { id: 16908, chapter: "Stretch Zone", title: "Carboxylic Acids: Fischer Esterification", prompt: "Fischer esterification of a carboxylic acid with an alcohol is an equilibrium process. How is the yield of ester typically maximized?", correct: "By adding excess alcohol or continuously removing water.", wrong: [["By cooling the reaction to 0\u00b0C.", "It is typically refluxed (heated) to drive the reaction.", "Apply Le Chatelier's principle."], ["By adding excess water.", "Adding water drives the equilibrium backward to the carboxylic acid.", "Water is a product."], ["By using a strong base catalyst.", "Fischer esterification is strictly acid-catalyzed.", "Base would deprotonate the acid, halting the reaction."]] },
    { id: 16909, chapter: "Stretch Zone", title: "Mechanisms: EAS", prompt: "A nitro group (-NO2) on a benzene ring directs incoming electrophiles to which position?", correct: "Meta, because it is strongly electron-withdrawing and deactivates the ortho/para positions.", wrong: [["Ortho/Para, because it donates electron density.", "It has a full positive charge on nitrogen; it withdraws electrons.", "Draw the resonance structures."], ["Meta, because it is an electron-donating group.", "It is meta-directing, but because it is withdrawing.", "Deactivators (except halogens) are meta directors."], ["It prevents all substitution entirely.", "It heavily deactivates the ring, but reactions can still occur under forcing conditions.", "The meta position is simply the least deactivated."]] },
    { id: 16910, chapter: "Stretch Zone", title: "Grignard Reagents", prompt: "Grignard reagents are incompatible with which of the following functional groups?", correct: "Carboxylic acids, because the Grignard reagent will act as a base and deprotonate the acid instead of acting as a nucleophile.", wrong: [["Ethers, because they form an explosive complex.", "Ethers (like THF or diethyl ether) are the standard solvents for Grignards.", "Grignards are extremely strong bases."], ["Ketones, because they undergo elimination.", "Ketones are standard electrophiles for Grignard addition.", "Acid-base chemistry is much faster than nucleophilic attack."], ["Alkanes, because they polymerize.", "Alkanes are inert to Grignards.", "Look for acidic protons."]] },
  ]),
  neuroscience: makeQuestionBank('University', [
    { id: 16401, chapter: 'Neuroscience Dock', title: 'Neuron job', prompt: 'A neuron primarily helps the body:', correct: 'Send and process signals', wrong: [['Digest food directly', 'Digestion is not the neuron’s main role.', 'Neurons are communication cells.'], ['Grow tree bark', 'That is unrelated.', 'Focus on signaling.'], ['Turn bones into cartilage', 'That is not nervous system function.', 'Use the communication idea.']] },
    { id: 16402, chapter: 'Neuroscience Reef', title: 'Synapse clue', prompt: 'A synapse is the place where:', correct: 'One neuron communicates with another cell', wrong: [['Blood is made', 'That happens in bone marrow, not at synapses.', 'A synapse is a communication junction.'], ['Teeth are repaired', 'That is unrelated.', 'Think cell-to-cell signal transfer.'], ['Bones lengthen overnight', 'That is not a neural process.', 'Stay with communication between cells.']] },
    { id: 16403, chapter: 'Neuroscience Cove', title: 'Brain region', prompt: 'The cerebrum is strongly associated with:', correct: 'Higher thinking and conscious processing', wrong: [['Only fingernail growth', 'That is unrelated.', 'Cerebrum is a major thinking center.'], ['Only red blood cell count', 'That is not its main function.', 'Keep the brain-role mapping clear.'], ['Photosynthesis', 'That is plant biology, not neuroscience.', 'Use the higher-processing clue.']] },
    { id: 16404, chapter: 'Neuroscience Lagoon', title: 'Neurotransmitter role', prompt: 'A neurotransmitter is best described as:', correct: 'A chemical messenger used in neural communication', wrong: [['A bone in the wrist', 'That is anatomy, not neural chemistry.', 'Neurotransmitters carry signals chemically.'], ['A type of microscope', 'That is unrelated.', 'Think messenger molecule.'], ['A weather system', 'That is not biology.', 'Use the communication function.']] },
    { id: 16405, chapter: 'Cognitive Neuroscience', title: 'Hippocampus Function', prompt: 'The primary role of the hippocampus in the brain is:', correct: 'Formation of new declarative memories', wrong: [["Direct control of muscle movement", "The motor cortex and cerebellum handle movement.", "Think of Patient H.M. who lost memory after hippocampal removal."], ["Regulation of heartbeat and breathing", "The brainstem (medulla) controls these autonomic functions.", "The hippocampus is part of the limbic system."], ["Primary processing of visual information", "The occipital lobe handles vision.", "Hippocampus = memory map."]] },
    { id: 16406, chapter: 'Neuroanatomy', title: 'Neuron Structure', prompt: 'Which part of the neuron is primarily responsible for receiving incoming signals from other neurons?', correct: 'Dendrites', wrong: [["Axon", "The axon carries signals away from the cell body.", "Dendrites are like \"ears\" for signals."], ["Axon Hillock", "The hillock is where the decision to fire an action potential is made.", "It is the start of the axon."], ["Terminal Boutons", "These are at the end of the axon and release neurotransmitters.", "Receiving happens at the other end."]] },
    { id: 16407, chapter: 'Synaptic Transmission', title: 'Major Neurotransmitters', prompt: 'What is the primary excitatory neurotransmitter in the vertebrate central nervous system?', correct: 'Glutamate', wrong: [["GABA", "GABA is the primary inhibitory neurotransmitter.", "Glutamate \"excites\" neurons."], ["Serotonin", "Serotonin is a neuromodulator involved in mood and sleep.", "Glutamate is the main fast-acting excitatory signal."], ["Dopamine", "Dopamine is involved in reward and motor control.", "Think of the most abundant excitatory signal."]] },
    { id: 16408, chapter: 'Neuroanatomy', title: 'Brain Lobes', prompt: 'Which lobe of the brain is most associated with executive functions like planning and decision-making?', correct: 'Frontal Lobe', wrong: [["Occipital Lobe", "Occipital is for vision.", "Frontal is at the \"front\" for planning."], ["Temporal Lobe", "Temporal is for hearing and memory.", "Decision-making happens in the prefrontal cortex."], ["Parietal Lobe", "Parietal is for sensory integration and spatial awareness.", "Executive function is frontal."]] },
    { id: 16409, chapter: 'Neurophysiology', title: 'Myelin Function', prompt: 'Myelin sheaths speed up signal conduction through a process called:', correct: 'Saltatory conduction', wrong: [["Slow-wave propagation", "Myelin actually makes signals much faster.", "Signals \"jump\" between nodes."], ["Chemical diffusion", "Conduction is electrical; diffusion is too slow for long axons.", "Think of the \"saltare\" (to jump)."], ["Active transport", "Active transport moves molecules across membranes, but doesn't explain the speed of the impulse.", "The gaps are called Nodes of Ranvier."]] },
    { id: 16410, chapter: 'Neurophysiology', title: 'Na+/K+ Pump', prompt: 'The sodium-potassium pump (Na+/K+-ATPase) maintains the resting potential by pumping:', correct: '3 Na+ out for every 2 K+ in', wrong: [["2 Na+ out for every 3 K+ in", "The pump moves more positive charge out than in, helping keep the inside negative.", "3-out, 2-in."], ["1 Na+ out for every 1 K+ in", "This would be electrically neutral.", "It must be asymmetrical to maintain the gradient."], ["3 K+ out for every 2 Na+ in", "Sodium is high outside; the pump keeps it that way by pumping it out.", "Sodium (Na) starts with N, and is pumped out (o)."]] },
    { id: 16411, chapter: 'Synaptic Transmission', title: 'Receptor Types', prompt: 'Which type of receptor acts faster because it is itself an ion channel?', correct: 'Ionotropic receptor', wrong: [["Metabotropic receptor", "Metabotropic receptors use G-proteins and second messengers, making them slower.", "Ionotropic = ion-channel-linked."], ["G-protein coupled receptor (GPCR)", "GPCR is another name for a metabotropic receptor.", "Think \"ligand-gated ion channel\"."], ["Nuclear receptor", "These involve gene transcription and are the slowest of all.", "Ionotropic is the \"fast\" synaptic transmission."]] },
    { id: 16412, chapter: 'Cognitive Neuroscience', title: 'Language Areas', prompt: 'A patient who can understand speech but has great difficulty producing it likely has a lesion in:', correct: 'Broca\'s Area', wrong: [["Wernicke's Area", "Wernicke's aphasia involves fluent but nonsensical speech (\"word salad\").", "Broca = Broken speech."], ["The Primary Visual Cortex", "This would affect vision, not language production.", "Language is usually in the left hemisphere."], ["The Cerebellum", "The cerebellum coordinates movement but isn't the primary site for language production.", "Production of words is Broca's."]] },
    { id: 16413, chapter: 'Neurophysiology', title: 'Refractory Periods', prompt: 'The absolute refractory period is primarily caused by:', correct: 'Inactivation of voltage-gated Na+ channels', wrong: [["The cell being too negative", "That describes the relative refractory period (hyperpolarization).", "Sodium channels must reset before another spike is possible."], ["The Na+/K+ pump stopping", "The pump works constantly and doesn't cause the refractory period.", "It's about the state of the channels."], ["Too much neurotransmitter in the cleft", "Refractory periods are a property of the axon membrane, not the synapse.", "Think of the h-gate closing."]] },
    { id: 16414, chapter: 'Synaptic Transmission', title: 'Neurotransmitter Release', prompt: 'Which ion is directly responsible for triggering the fusion of synaptic vesicles with the presynaptic membrane?', correct: 'Calcium (Ca2+)', wrong: [["Sodium (Na+)", "Sodium causes the depolarization that opens the calcium channels, but isn't the final trigger.", "Calcium influx is the key step."], ["Potassium (K+)", "Potassium usually exits the cell to repolarize it.", "Calcium is the signal for exocytosis."], ["Chloride (Cl-)", "Chloride is usually inhibitory.", "Think of the voltage-gated Ca2+ channels at the terminal."]] },
    { id: 16415, chapter: 'Neurophysiology', title: 'Nernst Equation', prompt: 'If the concentration of K+ is 100 mM inside and 10 mM outside, what is the approximate equilibrium potential for K+ at body temperature?', correct: '-61 mV', wrong: [["+61 mV", "Potassium is positive and higher inside, so it will flow out, leaving the inside negative.", "Log(out/in) = Log(0.1) = -1."], ["0 mV", "Equilibrium potentials only occur when there is no concentration gradient or an opposing electrical force.", "The gradient is 10:1."], ["-90 mV", "-90 mV is the typical resting potential, which is close to but not identical to the K+ equilibrium.", "61 * log(10/100) = -61."]] },
    { id: 16416, chapter: 'Cognitive Neuroscience', title: 'Molecular Basis of LTP', prompt: 'During Long-Term Potentiation (LTP), the increase in synaptic strength is primarily due to:', correct: 'Insertion of additional AMPA receptors into the postsynaptic membrane', wrong: [["Destruction of NMDA receptors", "NMDA receptors are essential for triggering LTP, not for the lasting strength increase.", "AMPA receptors handle the bulk of the EPSP."], ["The neuron growing a second nucleus", "Neurons don't grow new nuclei.", "Plasticity is at the synapse level."], ["Decreasing the amount of Glutamate released", "LTP is usually postsynaptic (though presynaptic components exist).", "Think of increased sensitivity to Glutamate."]] },
    { id: 16417, chapter: 'Sensory Systems', title: 'Phototransduction', prompt: 'In the dark, vertebrate photoreceptors (rods and cones) are:', correct: 'Depolarized and continuously releasing glutamate', wrong: [["Hyperpolarized and silent", "Light actually causes hyperpolarization in vertebrate eyes.", "Darkness = \"on\" state for release."], ["Firing rapid action potentials", "Photoreceptors are graded-potential cells; they don't fire action potentials.", "They use continuous release."], ["Inactivated by rhodopsin", "Rhodopsin is activated by light, not darkness.", "cGMP levels are high in the dark, keeping channels open."]] },
    { id: 16418, chapter: 'Synaptic Transmission', title: 'SNARE Proteins', prompt: 'The primary role of the SNARE protein complex in the synapse is to:', correct: 'Pull the vesicle and presynaptic membrane together for fusion', wrong: [["Synthesize neurotransmitters", "Enzymes in the cytoplasm or mitochondria do this.", "SNAREs are \"docking\" proteins."], ["Pump ions back into the vesicle", "V-ATPases handle vesicle acidification and loading.", "Think of a winch pulling the vesicle to the wall."], ["Act as a receptor for Dopamine", "SNAREs are intracellular structural proteins, not receptors.", "They respond to the Calcium sensor (Synaptotagmin)."]]},
    { id: 16419, chapter: 'Sensory Systems', title: 'Basal Ganglia Circuit', prompt: 'In the basal ganglia "direct pathway", the net effect on the thalamus (and thus motor output) is:', correct: 'Disinhibition (Excitation)', wrong: [["Increased inhibition (Suppression)", "The direct pathway inhibits an inhibitor, leading to excitation.", "Direct = Go; Indirect = No-go."], ["Direct electrical connection", "The connection is chemical (GABA and Glutamate).", "Think of the \"double negative\" logic."], ["Bypassing the motor cortex", "The basal ganglia project back to the cortex via the thalamus.", "They modulate, not bypass."]] },
    { id: 16420, chapter: 'Neuroanatomy', title: 'Homunculus Organization', prompt: 'On the somatosensory homunculus, why are the hands and lips represented by much larger cortical areas than the back?', correct: 'They have a much higher density of sensory receptors and smaller receptive fields', wrong: [["They are physically closer to the brain", "Physical distance doesn't determine cortical representation.", "Representation is based on functional importance."], ["They use more blood flow during movement", "fMRI measures blood flow, but the map itself is built on receptor density.", "Think of fine motor control vs broad sensation."], ["The back is processed in the cerebellum instead", "All somatosensory info goes to the parietal lobe map.", "Magnification reflects sensitivity."]] },
    { id: 16421, chapter: 'Cognitive Neuroscience', title: 'NMDA Coincidence Detection', prompt: 'The NMDA receptor is called a "coincidence detector" because it only opens when:', correct: 'Glutamate is present AND the postsynaptic membrane is already depolarized', wrong: [["Two different neurotransmitters bind simultaneously", "It only binds Glutamate (and Glycine).", "The second \"event\" is electrical."], ["The neuron fires an action potential AND it is daytime", "Circadian rhythms affect the brain, but not the NMDA channel mechanism directly.", "It requires Magnesium to be expelled."], ["Calcium is high inside AND outside", "Calcium flows through it, it isn't the trigger for opening.", "Depolarization removes the Mg2+ block."]] },
    { id: 16422, chapter: 'Stretch Zone', title: 'fMRI BOLD Signal', prompt: 'The fMRI BOLD (Blood-Oxygen-Level-Dependent) signal actually measures:', correct: 'The ratio of oxygenated to deoxygenated hemoglobin', wrong: [["Direct electrical activity of neurons", "fMRI is an indirect measure; EEG measures electrical activity.", "Neurons don't contain hemoglobin."], ["The number of action potentials per second", "It measures the metabolic response to neural activity, which is a proxy.", "The delay is about 5-6 seconds."], ["The amount of glucose consumed by the brain", "PET scans often use glucose tracers; fMRI focuses on oxygen levels.", "Active neurons demand more oxygenated blood."]] },
    { id: 16423, chapter: 'Cognitive Neuroscience', title: 'Neurodegeneration', prompt: 'Parkinson\'s Disease is primarily characterized by the death of neurons in the:', correct: 'Substantia Nigra', wrong: [["Hippocampus", "Hippocampal cell death is more characteristic of Alzheimer's.", "Substantia Nigra = Black substance."], ["Amygdala", "The amygdala is for emotion; its dysfunction is linked to anxiety/fear disorders.", "Parkinson's starts with motor issues."], ["Prefrontal Cortex", "This is linked to executive dysfunction and personality changes.", "Think Dopamine production centers."]] },
    { id: 16424, chapter: 'Synaptic Transmission', title: 'Summation', prompt: 'If a neuron receives three excitatory inputs (EPSPs) at the exact same location but staggered in time, this is an example of:', correct: 'Temporal summation', wrong: [["Spatial summation", "Spatial summation is inputs from different locations arriving at the same time.", "Temporal = time."], ["Inhibitory cancellation", "EPSPs are excitatory; they don't cancel each other.", "They add up toward the threshold."], ["Action potential refractory", "Summation happens before the action potential is triggered.", "Think \"time\" (temporal)."]]},
    { id: 17001, chapter: "Stretch Zone", title: "Action Potentials", prompt: "The absolute refractory period of a neuron is primarily caused by:", correct: "The inactivation of voltage-gated sodium channels.", wrong: [["The delayed closing of potassium channels.", "That causes the relative refractory period (hyperpolarization).", "The sodium channels plug themselves with an inactivation gate."], ["The depletion of ATP in the sodium-potassium pump.", "The pump works continuously and slowly; it doesn't cause the rapid refractory period.", "It happens immediately after the peak of the action potential."], ["The physical exhaustion of neurotransmitters.", "That is synaptic fatigue, not the axonal refractory period.", "Think ion channels."]] },
    { id: 17002, chapter: "Stretch Zone", title: "Synaptic Transmission", prompt: "The primary role of the SNARE complex in the presynaptic terminal is to:", correct: "Mediate the fusion of synaptic vesicles with the presynaptic membrane upon calcium entry.", wrong: [["Synthesize neurotransmitters.", "Enzymes do this, not SNARE proteins.", "It's about vesicle release."], ["Reuptake neurotransmitters from the cleft.", "Transporters (like SERT or DAT) handle reuptake.", "It 'snares' the vesicle to the membrane."], ["Generate the action potential.", "Voltage-gated ion channels do that.", "It facilitates exocytosis."]] },
    { id: 17003, chapter: "Stretch Zone", title: "Neuroanatomy: Basal Ganglia", prompt: "The indirect pathway of the basal ganglia serves primarily to:", correct: "Inhibit competing or unwanted motor movements.", wrong: [["Facilitate and execute voluntary movement.", "That is the role of the direct pathway.", "It acts as a 'brake'."], ["Process auditory stimuli.", "The basal ganglia are primarily motor/cognitive.", "It sends inhibitory signals to the thalamus."], ["Control autonomic functions like heart rate.", "The brainstem handles that.", "Think Parkinson's and Huntington's diseases."]] },
    { id: 17004, chapter: "Stretch Zone", title: "Sensory Systems: Phototransduction", prompt: "In the dark, photoreceptor cells (rods) are continuously releasing glutamate because:", correct: "High levels of cGMP keep cyclic nucleotide-gated (CNG) sodium/calcium channels open, depolarizing the cell.", wrong: [["Light directly closes potassium channels.", "Light activates rhodopsin, which activates phosphodiesterase to break down cGMP.", "The 'dark current' is a depolarizing current."], ["Glutamate is required to maintain the physical structure of the retina.", "It is a neurotransmitter signaling 'darkness' to bipolar cells.", "Photoreceptors are depolarized in the dark."], ["They are undergoing apoptosis.", "This is normal physiological function.", "cGMP is the key messenger."]] },
    { id: 17005, chapter: "Stretch Zone", title: "Memory: LTP", prompt: "The NMDA receptor acts as a coincidence detector in LTP because it requires both:", correct: "Glutamate binding and postsynaptic depolarization to expel the magnesium block.", wrong: [["GABA and calcium binding.", "It is a glutamate receptor.", "It needs pre- and post-synaptic activity simultaneously."], ["ATP and sodium entry.", "It allows calcium entry, not just sodium.", "The magnesium ion literally plugs the pore at resting potential."], ["Presynaptic inhibition and postsynaptic excitation.", "It requires excitation on both sides (Hebb's rule).", "Depolarization removes the Mg2+ block."]] },
    { id: 17006, chapter: "Stretch Zone", title: "Neurotransmitters: GABA", prompt: "GABA-A receptors mediate fast inhibitory synaptic transmission by:", correct: "Opening chloride channels, leading to hyperpolarization of the postsynaptic membrane.", wrong: [["Opening sodium channels.", "Sodium entry causes depolarization (excitation).", "Chloride is negatively charged."], ["Activating G-proteins to close potassium channels.", "That describes GABA-B receptors (which are metabotropic and open K+ channels).", "GABA-A is ionotropic (fast)."], ["Blocking calcium entry directly.", "It hyperpolarizes the cell away from the action potential threshold.", "Cl- flows in."]] },
    { id: 17007, chapter: "Stretch Zone", title: "Development: Growth Cones", prompt: "Axonal growth cones navigate toward their targets by responding to:", correct: "Attractive and repulsive guidance cues (like netrins and semaphorins) in the extracellular environment.", wrong: [["Magnetic fields generated by the target cells.", "The brain does not use magnetism for axon guidance.", "They use chemical gradients."], ["Pre-existing myelin sheaths.", "Myelination happens after the axons reach their targets.", "Think chemotaxis."], ["Random trial and error until they hit the right spot.", "The wiring is highly specific and guided.", "Filopodia sample the chemical environment."]] },
    { id: 17008, chapter: "Stretch Zone", title: "Cortical Organization", prompt: "The homunculus in the primary somatosensory cortex demonstrates that:", correct: "The area of cortex dedicated to a body part is proportional to its sensory receptor density, not its physical size.", wrong: [["The cortex perfectly mirrors the physical proportions of the body.", "The hands and lips are massively overrepresented.", "It represents tactile acuity."], ["Only the arms and legs are mapped in the cortex.", "The entire body surface is mapped.", "Think of the two-point discrimination threshold."], ["The map is completely random and unstructured.", "It is topographically organized (somatotopy).", "More receptors = more cortical real estate."]] },
    { id: 17009, chapter: "Stretch Zone", title: "Motor Systems: Cerebellum", prompt: "Damage to the cerebellum typically results in:", correct: "Ataxia, characterized by uncoordinated and inaccurate voluntary movements.", wrong: [["Complete paralysis.", "Paralysis is caused by motor cortex or spinal cord damage.", "The cerebellum coordinates, it doesn't initiate."], ["Resting tremors.", "Resting tremors are typical of Parkinson's (basal ganglia). Cerebellar damage causes intention tremors.", "It calibrates movement in real-time."], ["Loss of all sensation.", "The cerebellum is a motor structure.", "Think 'clumsiness' or 'drunken gait'."]] },
    { id: 17010, chapter: "Stretch Zone", title: "Glial Cells", prompt: "Astrocytes play a critical role at the tripartite synapse by:", correct: "Clearing excess neurotransmitters like glutamate from the synaptic cleft to prevent excitotoxicity.", wrong: [["Myelinating axons in the central nervous system.", "Oligodendrocytes do that.", "Astrocytes regulate the chemical environment."], ["Firing action potentials to boost the signal.", "Astrocytes do not fire action potentials.", "They are support cells."], ["Acting as the primary immune cells of the brain.", "Microglia are the immune cells.", "They use transporters to vacuum up glutamate."]] },
  ]),
  researchMethods: makeQuestionBank('University', [
    { id: 16501, chapter: 'Research Methods Dock', title: 'Hypothesis', prompt: 'A hypothesis is:', correct: 'A testable statement or prediction', wrong: [['A final proven law', 'Hypotheses are tested, not assumed proven.', 'Think testable starting claim.'], ['A list of every citation', 'That is bibliography work, not hypothesis.', 'Keep method pieces separate.'], ['A random decoration in a paper', 'That is unrelated.', 'Research starts with a testable idea.']] },
    { id: 16502, chapter: 'Research Methods Reef', title: 'Data type', prompt: 'Quantitative data is expressed using:', correct: 'Numbers and measurements', wrong: [['Only poems', 'Poems are qualitative narrative, not quantitative.', 'Quantitative means quantity/numbers.'], ['Only hand signals', 'That is a communication method, not a data type.', 'Focus on the numerical aspect.'], ['Only invisible ink', 'That is about secrecy, not data type.', 'Choose the numerical clue.']] },
    { id: 16503, chapter: 'Research Methods Cove', title: 'Variable clue', prompt: 'The variable you change to see its effect is the:', correct: 'Independent variable', wrong: [['The weather variable', 'Unless you are a weather researcher, this is too narrow.', 'Think of the one you manipulate.'], ['The constant variable', 'Constants stay the same.', 'Independent variables are changed.'], ['The dependent variable', 'The dependent variable is the outcome you measure.', 'Focus on the one you control.']] },
    { id: 16504, chapter: 'Research Methods Lagoon', title: 'Sample idea', prompt: 'A sample is a subset of:', correct: 'A larger population', wrong: [['Only one single atom', 'A sample is usually a group of subjects.', 'Think of a representative subset.'], ['The planet Jupiter', 'Unless you study Jupiter, this is too broad.', 'Use the population-subset definition.'], ['Every person who ever lived', 'That is the entire population of history.', 'A sample is a smaller, manageable group.']] },
    { id: 16505, chapter: 'Foundations of Research', title: 'Independent Variable', prompt: 'In an experiment testing the effect of caffeine on test scores, caffeine is the:', correct: 'Independent Variable', wrong: [["Dependent Variable", "The dependent variable is the outcome being measured (the test scores).", "Independent = what you change."], ["Confounding Variable", "A confounding variable is an outside factor that might influence results.", "Caffeine is the intentional variable."], ["Control Group", "The control group is the set of people NOT receiving caffeine.", "Variable = the thing that varies."]] },
    { id: 16506, chapter: 'Foundations of Research', title: 'Hypothesis Types', prompt: 'The hypothesis that states there is NO relationship between variables is called the:', correct: 'Null Hypothesis (H0)', wrong: [["Alternative Hypothesis (H1)", "The alternative hypothesis states that there IS a relationship.", "Null means \"zero\" or \"none\"."], ["Scientific Law", "A law is an established principle, not a starting prediction.", "Think of the \"default\" assumption in statistics."], ["Qualitative Hypothesis", "This isn't a standard term in hypothesis testing.", "Null vs Alternative is the key pairing."]] },
    { id: 16507, chapter: 'Experimental Design', title: 'Quantitative Data', prompt: 'Which of the following is an example of quantitative data?', correct: 'The temperature of a liquid in degrees Celsius', wrong: [["A person's description of their mood", "Descriptions are qualitative (narrative) data.", "Quantitative = numerical."], ["The color of a car", "Color is categorical/qualitative data.", "Think about whether you can do math with the data."], ["A video of an animal's behavior", "Visual recordings are qualitative until they are coded numerically.", "Measurements are quantitative."]] },
    { id: 16508, chapter: 'Measurement', title: 'Reliability vs Validity', prompt: 'If a scale consistently gives you the same weight every time you step on it, but that weight is 10 lbs too low, the scale is:', correct: 'Reliable but not valid', wrong: [["Valid but not reliable", "It isn't valid because it's wrong, and it is reliable because it's consistent.", "Reliability = consistency."], ["Neither reliable nor valid", "It is consistent, so it meets the definition of reliability.", "Consistency is the key for reliability."], ["Both reliable and valid", "It isn't valid because it doesn't measure the correct weight.", "Validity = accuracy of measurement."]] },
    { id: 16509, chapter: 'Statistical Analysis', title: 'Central Tendency', prompt: 'In a dataset with extreme outliers (like a few billionaires in a small town), which measure of central tendency is most representative of the "average" person?', correct: 'Median', wrong: [["Mean", "The mean is heavily influenced by outliers and will be skewed upward.", "Median is the middle value."], ["Mode", "The mode is just the most frequent value, which might not be central at all.", "Median resists skew."], ["Standard Deviation", "Standard deviation measures spread, not center.", "Think about \"middle\" income."]] },
    { id: 16510, chapter: 'Sampling', title: 'Sampling Methods', prompt: 'A researcher divides a population into groups (like age brackets) and then takes a random sample from EACH group. This is:', correct: 'Stratified Random Sampling', wrong: [["Cluster Sampling", "In cluster sampling, you pick entire groups at random, not individuals from every group.", "Stratified ensures every group is represented."], ["Convenience Sampling", "Convenience sampling is picking people who are easy to reach.", "Randomness is required for stratification."], ["Systematic Sampling", "Systematic sampling is picking every \"nth\" person.", "Divide into strata first."]] },
    { id: 16511, chapter: 'Statistical Analysis', title: 'Type I vs Type II Error', prompt: 'A Type I Error occurs when a researcher:', correct: 'Rejects a null hypothesis that is actually true (False Positive)', wrong: [["Fails to reject a null hypothesis that is actually false (False Negative)", "That is a Type II Error.", "Type I is finding an effect where none exists."], ["Accepts the alternative hypothesis as a law", "Researchers \"fail to reject\" or \"reject\", they don't usually \"prove\" laws.", "Think \"innocent person found guilty\"."], ["Makes a math error in the calculation", "While it can happen, Type I/II refers to the decision error relative to reality.", "Alpha vs Beta."]] },
    { id: 16512, chapter: 'Measurement', title: 'Levels of Measurement', prompt: 'A variable like "Class Rank" (1st, 2nd, 3rd) is measured at which level?', correct: 'Ordinal', wrong: [["Nominal", "Nominal data has no order (like hair color).", "Rank implies an order."], ["Interval", "Interval data has consistent gaps but no true zero (like Celsius).", "We don't know if the gap between 1st and 2nd is the same as 2nd and 3rd."], ["Ratio", "Ratio data has a true zero (like height).", "Ranks are ordered categories."]] },
    { id: 16513, chapter: 'Experimental Design', title: 'RCT Benefits', prompt: 'The primary advantage of a Randomized Controlled Trial (RCT) is that it:', correct: 'Minimizes selection bias and allows for causal inference', wrong: [["Is the cheapest way to do research", "RCTs are often very expensive and time-consuming.", "Quality comes at a cost."], ["Requires the smallest sample size", "RCTs often need large samples to detect effects.", "The benefit is about internal validity."], ["Can be done without any ethical review", "RCTs involving humans require strict ethical oversight.", "Randomization is the key to balance."]] },
    { id: 16514, chapter: 'Statistical Analysis', title: 'p-value Definition', prompt: 'A p-value of 0.05 means:', correct: 'There is a 5% chance of obtaining these results if the null hypothesis is true', wrong: [["There is a 95% chance the hypothesis is true", "A p-value is about the data given the hypothesis, not the hypothesis given the data.", "It measures \"surprisingness\"."], ["The effect size is 5%", "p-values measure significance, not the magnitude of the effect.", "Small p-values can come from tiny effects in huge samples."], ["5% of the data was incorrect", "p-values are a probability calculation, not an error count.", "Think probability of \"fluke\" results."]] },
    { id: 16515, chapter: 'Experimental Design', title: 'Internal Validity Threats', prompt: 'In a year-long study on a new teaching method, students naturally get older and wiser. This threat to internal validity is called:', correct: 'Maturation', wrong: [["History", "History refers to external events (like a war or news story) affecting participants.", "Internal biological/psychological change is maturation."], ["Instrumentation", "Instrumentation refers to the test or observer changing over time.", "The students themselves are changing here."], ["Selection Bias", "Selection bias is a problem with how groups were formed at the start.", "This is change \"during\" the study."]] },
    { id: 16516, chapter: 'Experimental Design', title: 'Regression Discontinuity', prompt: 'A Regression Discontinuity design is often used when an intervention is assigned based on:', correct: 'A strict cutoff score on a pre-existing metric (e.g., scholarship eligibility)', wrong: [["A random coin flip", "That would be a standard RCT.", "RD is for non-random assignments with a clear threshold."], ["The participant's choice", "Participant choice leads to self-selection bias.", "RD uses the \"random-like\" variation near the cutoff."], ["The researcher's intuition", "Intuition is not a systematic assignment rule.", "RD is a quasi-experimental method."]] },
    { id: 16517, chapter: 'Measurement', title: 'Statistical Power', prompt: 'Which of the following would DECREASE the statistical power of a study?', correct: 'Reducing the sample size', wrong: [["Increasing the effect size", "Larger effects are easier to find, which increases power.", "Power is the ability to find an effect."], ["Using a more sensitive measurement tool", "Better tools reduce noise and increase power.", "Power = 1 - Beta."], ["Lowering the alpha level (e.g., from 0.05 to 0.01)", "This actually increases the chance of a Type II error (beta), thus decreasing power.", "Think \"lower significance threshold makes effects harder to claim\"."]] },
    { id: 16518, chapter: 'Experimental Design', title: 'Confounding Control', prompt: 'If you cannot randomize, but you ensure that for every 20-year-old male in the treatment group, there is a 20-year-old male in the control group, you are using:', correct: 'Matching', wrong: [["Double-blinding", "Blinding is about keeping people unaware of their group.", "This is about group composition."], ["Randomization", "You are intentionally picking individuals, not using a random process.", "Matching is a quasi-experimental control."], ["Statistical regression", "Regression is a data analysis technique, not an assignment method.", "Think of \"pair-wise\" balance."]] },
    { id: 16519, chapter: 'Research Ethics', title: 'Belmont Principles', prompt: 'Ensuring that the risks of research are not borne solely by a vulnerable population (like prisoners) while benefits go to the wealthy is an application of:', correct: 'Justice', wrong: [["Beneficence", "Beneficence is about maximizing benefits and minimizing harms for the participants.", "Justice is about fair distribution of burdens and benefits."], ["Respect for Persons", "Respect for persons is about autonomy and informed consent.", "Equity is the key for justice."], ["Fidelity", "Fidelity is about faithfulness and trust, but not the primary Belmont principle for distribution.", "Think \"fairness\"."]] },
    { id: 16520, chapter: 'Statistical Analysis', title: 'Replication Crisis', prompt: 'The practice of "p-hacking" involves:', correct: 'Trying different statistical tests until one yields a significant p-value', wrong: [["Stealing data from other researchers", "That is data theft or plagiarism.", "p-hacking is about manipulating the analysis process."], ["Predicting results after looking at the data (HARKing)", "HARKing is a related but distinct problem in the replication crisis.", "p-hacking is about the p-value itself."], ["Publishing only successful studies", "That is \"publication bias\" or the \"file drawer problem\".", "Hack = manipulation of the math/process."]] },
    { id: 16521, chapter: 'Statistical Analysis', title: 'Test Selection', prompt: 'If you want to compare the mean test scores of THREE different groups (low, medium, and high caffeine), the most appropriate test is:', correct: 'One-way ANOVA', wrong: [["Independent samples t-test", "T-tests can only compare TWO groups.", "ANOVA is for more than two."], ["Pearson Correlation", "Correlation is for two continuous variables, not group means.", "Compare means across categories."], ["Chi-Square", "Chi-Square is for categorical outcome variables.", "Test scores are usually continuous."]] },
    { id: 16522, chapter: 'Measurement', title: 'Construct Validity', prompt: 'Construct validity refers to how well a test:', correct: 'Actually measures the theoretical concept it claims to measure (e.g., intelligence)', wrong: [["Covers all aspects of the subject (Content Validity)", "Content validity is about the breadth of the material.", "Construct is about the \"hidden\" theory."], ["Predicts future outcomes (Criterion Validity)", "Criterion validity is about external benchmarks.", "Think \"theoretical mapping\"."], ["Is consistent over time (Reliability)", "Reliability is NOT validity.", "Does the test match the concept?"]]},
    { id: 16523, chapter: 'Foundations of Research', title: 'Systematic vs Scoping', prompt: 'A "Scoping Review" is typically conducted when the primary goal is to:', correct: 'Map the existing literature and identify the volume and nature of research on a broad topic', wrong: [["Provide a definitive answer to a very specific clinical question", "That is the goal of a Systematic Review.", "Scoping is broader and exploratory."], ["Synthesize the data numerically using meta-analysis", "Scoping reviews usually don't involve meta-analysis.", "Think of \"scanning the landscape\"."], ["Review only the most famous papers in a field", "Scoping reviews should be systematic and comprehensive within their scope.", "It's about mapping, not answering specific narrow questions."]] },
    { id: 16524, chapter: 'Stretch Zone', title: 'Instrumental Variables', prompt: 'In causal inference, an "Instrumental Variable" is a third variable that is correlated with the ____ but only affects the ____ through its effect on the former.', correct: 'Independent Variable; Dependent Variable', wrong: [["Dependent Variable; Independent Variable", "The instrument should not be directly linked to the outcome.", "It acts as a \"random-ish\" lever for the treatment."], ["Control Group; Treatment Group", "Instruments are variables, not groups.", "Think of an instrument as a \"nudge\"."], ["Confounding Variable; Noise", "An instrument helps isolate the effect of the IV from confounding.", "It solves the endogeneity problem."]] },
    { id: 17101, chapter: "Stretch Zone", title: "Validity: Construct Validity", prompt: "Construct validity refers to the extent to which:", correct: "An operationalized measurement accurately captures the theoretical concept it is intended to measure.", wrong: [["The results can be generalized to the broader population.", "That is external validity.", "Think 'Are we actually measuring depression with this survey?'"], ["The experiment controls for all confounding variables.", "That is internal validity.", "It links theory to measurement."], ["The results are consistent over time.", "That is reliability.", "A measure can be reliable but invalid."]] },
    { id: 17102, chapter: "Stretch Zone", title: "Design: Double-Blind RCT", prompt: "The primary purpose of a double-blind design in a randomized controlled trial is to:", correct: "Prevent experimenter bias and participant demand characteristics from influencing the outcome.", wrong: [["Ensure the sample is perfectly representative of the population.", "Random sampling does that, not blinding.", "Blinding conceals the treatment assignment."], ["Eliminate the placebo effect entirely.", "It controls for the placebo effect by making both groups expect treatment equally.", "It keeps expectations symmetrical."], ["Ensure perfect compliance with the drug regimen.", "Blinding doesn't force patients to take their medicine.", "Neither the researcher nor patient knows who gets the real drug."]] },
    { id: 17103, chapter: "Stretch Zone", title: "Statistics: Type I Error", prompt: "A Type I error occurs when a researcher:", correct: "Rejects the null hypothesis when it is actually true (a false positive).", wrong: [["Fails to reject the null hypothesis when it is false.", "That is a Type II error (a false negative).", "Think 'crying wolf'."], ["Calculates the p-value incorrectly.", "It is a statistical decision error, not a math mistake.", "It means finding an effect that isn't really there."], ["Uses a biased sampling method.", "That is a methodological flaw, not a hypothesis testing error.", "Alpha controls the rate of Type I errors."]] },
    { id: 17104, chapter: "Stretch Zone", title: "Sampling: Stratified Random Sampling", prompt: "Stratified random sampling improves upon simple random sampling by:", correct: "Ensuring proportional representation of key demographic subgroups within the sample.", wrong: [["Guaranteeing that every person in the world has an equal chance of selection.", "No sample can do that.", "It divides the population into 'strata' first."], ["Eliminating all non-response bias.", "Stratification doesn't force people to answer the survey.", "It guarantees subgroups aren't left out by random chance."], ["Being much faster and cheaper to execute.", "It is usually more difficult and expensive because you must know the population breakdown first.", "It increases precision."]] },
    { id: 17105, chapter: "Stretch Zone", title: "Ethics: Belmont Report", prompt: "The ethical principle of 'Beneficence' outlined in the Belmont Report requires researchers to:", correct: "Maximize potential benefits to participants while minimizing potential harms.", wrong: [["Ensure participants provide informed consent.", "That falls under the principle of 'Respect for Persons'.", "Think 'do good, avoid harm'."], ["Distribute the risks and benefits of research equally across society.", "That is the principle of 'Justice'.", "It requires a risk-benefit analysis."], ["Pay participants a large sum of money.", "Coercive payment is actually unethical.", "Protect the participant's well-being."]] },
    { id: 17106, chapter: "Stretch Zone", title: "Qualitative: Grounded Theory", prompt: "The primary goal of Grounded Theory methodology is to:", correct: "Inductively generate a theoretical framework directly from the collected qualitative data.", wrong: [["Deductively test a pre-existing hypothesis.", "That is a quantitative approach.", "The theory is 'grounded' in the data."], ["Provide a rich, narrative biography of a single individual.", "That is Narrative Inquiry or a Case Study.", "It aims to explain a process or phenomenon."], ["Statistically prove the prevalence of a behavior.", "Grounded theory is qualitative.", "It uses constant comparison and theoretical sampling."]] },
    { id: 17107, chapter: "Stretch Zone", title: "Measurement: Reliability", prompt: "A measurement tool that yields highly consistent results but completely misses the target concept is said to have:", correct: "High reliability but low validity.", wrong: [["High validity but low reliability.", "If it's invalid, it misses the target.", "Think of a broken scale that always reads 100 lbs."], ["Low reliability and low validity.", "It is consistent, so it is reliable.", "It is precisely wrong."], ["High precision and high accuracy.", "Accuracy is synonymous with validity here.", "It is precise, but not accurate."]] },
    { id: 17108, chapter: "Stretch Zone", title: "Design: Quasi-Experimental", prompt: "What is the defining difference between a quasi-experimental design and a true experiment?", correct: "The lack of random assignment to treatment and control groups.", wrong: [["The absence of a control group entirely.", "Quasi-experiments often have control groups, they just aren't randomly assigned.", "Think pre-existing groups like two different classrooms."], ["The use of qualitative data instead of quantitative.", "Quasi-experiments use quantitative statistics.", "Randomization is the key to causal inference."], ["The study is conducted in a laboratory.", "True experiments are often in labs; quasi are often in the field.", "You cannot control who gets the treatment."]] },
    { id: 17109, chapter: "Stretch Zone", title: "Analysis: ANOVA", prompt: "When comparing the means of three or more independent groups, an ANOVA is preferred over multiple t-tests because:", correct: "Multiple t-tests inflate the family-wise error rate (the cumulative probability of a Type I error).", wrong: [["T-tests cannot handle continuous data.", "T-tests require continuous dependent variables.", "Running 3 t-tests increases the chance of a false positive."], ["ANOVA directly identifies which specific groups differ.", "ANOVA only tells you IF a difference exists; post-hoc tests tell you WHERE.", "It controls the alpha level for the whole experiment."], ["ANOVA does not require the assumption of normal distribution.", "Both ANOVA and t-tests assume normality.", "It prevents false positives."]] },
    { id: 17110, chapter: "Stretch Zone", title: "Mixed Methods", prompt: "In a 'Sequential Explanatory' mixed methods design:", correct: "Quantitative data is collected and analyzed first, followed by qualitative data to explain the quantitative results.", wrong: [["Qualitative data is collected first to build a survey.", "That is a Sequential Exploratory design.", "The qualitative explains the 'why' behind the quantitative 'what'."], ["Both are collected simultaneously and merged.", "That is a Convergent Parallel design.", "It happens in a specific order."], ["Only quantitative data is used.", "Then it wouldn't be a mixed methods design.", "Numbers first, interviews second."]] },
  ]),
  philosophy: makeQuestionBank('University', [
    { id: 16601, chapter: 'Philosophy Dock', title: 'Argument clue', prompt: 'A philosophical argument is mainly:', correct: 'A set of reasons supporting a conclusion', wrong: [['Any loud disagreement', 'Arguments in philosophy are about reasoning, not volume.', 'Focus on premises and conclusion.'], ['A costume change in a play', 'That is unrelated.', 'Think structured reasoning.'], ['A random question with no support', 'Philosophical arguments involve justification.', 'Reasons matter.']] },
    { id: 16602, chapter: 'Philosophy Reef', title: 'Knowledge idea', prompt: 'In many traditions, knowledge is often defined as:', correct: 'Justified true belief', wrong: [['A really good guess', 'A guess lacks justification even if true.', 'Think JTB.'], ['An angry shout', 'Shouting is not a definition of knowledge.', 'Use the classic tripartite definition.'], ['A colorful dream', 'Dreams are not the standard definition of knowledge.', 'Choose the belief-based clue.']] },
    { id: 16603, chapter: 'Philosophy Cove', title: 'Ethics focus', prompt: 'Ethics is the branch of philosophy that deals with:', correct: 'Moral values and right conduct', wrong: [['Only the price of gold', 'That is economics, not ethics.', 'Ethics is about behavior and values.'], ['How to build a car engine', 'That is engineering.', 'Focus on moral questions.'], ['The speed of light in a vacuum', 'That is physics.', 'Choose the conduct clue.']] },
    { id: 16604, chapter: 'Philosophy Lagoon', title: 'Logic tool', prompt: 'A "premise" in an argument is used to:', correct: 'Provide support or evidence for a conclusion', wrong: [['Decorate the margins of a book', 'Premises are functional parts of reasoning.', 'Think evidence.'], ['Identify the font size', 'That is unrelated.', 'Premises build the case.'], ['Translate words into music', 'That is not the role of a premise.', 'Use the support-for-conclusion idea.']] },
    { id: 16605, chapter: 'Doing Philosophy', title: 'Logical Validity', prompt: 'In philosophy, a "valid" deductive argument is one where:', correct: 'If the premises are true, the conclusion MUST be true', wrong: [["The conclusion is definitely true in the real world", "An argument can be valid even if the premises are false. Validity is about the structure.", "Validity = logical necessity given the premises."], ["The argument is written in very fancy language", "Logic is about reasoning, not style.", "A valid argument can be simple."], ["Everyone agrees with the conclusion", "Agreement doesn't determine logical validity.", "Think of the \"if... then...\" connection."]] },
    { id: 16606, chapter: 'Branches of Philosophy', title: 'Metaphysics vs Ethics', prompt: 'Which branch of philosophy studies the ultimate nature of reality, existence, and being?', correct: 'Metaphysics', wrong: [["Ethics", "Ethics studies right and wrong behavior and moral values.", "Metaphysics = \"after physics\"."], ["Epistemology", "Epistemology is the study of knowledge and belief.", "Think of the \"what is\" question."], ["Aesthetics", "Aesthetics studies beauty and art.", "Existence is a metaphysical question."]] },
    { id: 16607, chapter: 'Epistemology', title: 'Plato\'s Cave', prompt: 'In Plato\'s Allegory of the Cave, what do the shadows on the wall represent?', correct: 'The deceptive world of sensory appearances', wrong: [["The ultimate truth of reality", "The shadows are illusions; the sun outside represents the truth.", "Prisoners see shadows and think they are real."], ["The ghosts of dead philosophers", "The allegory is about knowledge and education, not ghosts.", "The cave is the physical world."], ["Evil demons trying to trick us", "Descartes used the evil demon; Plato used shadows and puppets.", "Think of \"appearance\" vs \"reality\"."]] },
    { id: 16608, chapter: 'Ethics', title: 'Utilitarianism', prompt: 'The core principle of Utilitarianism is to act in a way that produces:', correct: 'The greatest happiness for the greatest number', wrong: [["The most wealth for the individual", "That is egoism, not utilitarianism.", "Utilitarianism is impartial and altruistic."], ["The most beautiful works of art", "That would be a form of aestheticism.", "Utility is usually defined as pleasure or well-being."], ["Strict adherence to all laws", "Sometimes utility requires breaking a law if it prevents more suffering.", "Maximize the good."]] },
    { id: 16609, chapter: 'Doing Philosophy', title: 'Ad Hominem Fallacy', prompt: 'An "Ad Hominem" fallacy occurs when someone:', correct: 'Attacks the person making the argument rather than the argument itself', wrong: [["Misrepresents an opponent's position to make it easier to attack", "That is a Straw Man fallacy.", "Ad hominem = \"to the man\"."], ["Assumes the conclusion in one of the premises", "That is \"begging the question\" or circular reasoning.", "Focus on the personal attack."], ["Claims something is true just because a famous person said it", "That is an appeal to authority.", "Attacking the character, not the claim."]] },
    { id: 16610, chapter: 'Doing Philosophy', title: 'Modus Ponens', prompt: 'Which of the following represents the logical form "Modus Ponens"?', correct: 'If P then Q; P; Therefore Q', wrong: [["If P then Q; Q; Therefore P", "That is the fallacy of \"affirming the consequent\".", "Modus Ponens is the \"mode of putting\"."], ["If P then Q; Not Q; Therefore Not P", "That is \"Modus Tollens\" (the mode of taking).", "Start with P, get Q."], ["Either P or Q; Not P; Therefore Q", "That is a \"disjunctive syllogism\".", "Conditional reasoning."]] },
    { id: 16611, chapter: 'Epistemology', title: 'JTB Analysis', prompt: 'In the traditional \"JTB\" analysis, knowledge is defined as:', correct: 'Justified True Belief', wrong: [["Just the Truth itself", "You can have truth without knowing it (like a lucky guess).", "Knowledge needs a subject who believes it."], ["Anything you strongly feel is certain", "Feelings of certainty don't guarantee truth or justification.", "Belief is necessary but not sufficient."], ["Any belief that makes you happy", "Pragmatism might value useful beliefs, but JTB requires truth and reason.", "Check the three letters: J, T, B."]] },
    { id: 16612, chapter: 'Metaphysics', title: 'Ship of Theseus', prompt: 'The \"Ship of Theseus\" thought experiment primarily asks:', correct: 'Whether an object remains the same if all its parts are replaced over time', wrong: [["How much weight a wooden boat can carry", "That is a physics/engineering question.", "The problem is about \"numerical identity\"."], ["Whether ships can have souls", "The problem is usually applied to physical objects and persistence.", "Identity through change."], ["Why the Greeks were so good at sailing", "That is history, not metaphysics.", "If every plank is new, is it the \"same\" ship?"]]},
    { id: 16613, chapter: 'Ethics', title: 'Categorical Imperative', prompt: 'Immanuel Kant\'s \"Categorical Imperative\" suggests we should only act on rules that:', correct: 'We could consistently will to become a universal law', wrong: [["Make us feel the most satisfied", "Kant rejected feelings (inclinations) as the basis for morality.", "Duty is universal."], ["Our parents and teachers told us to follow", "Kant emphasized autonomy (giving the law to oneself).", "The \"Universal Law\" formulation."], ["Lead to the best consequences for everyone", "That is Utilitarianism, which Kant opposed.", "Focus on the \"form\" of the action, not the results."]] },
    { id: 16614, chapter: 'Philosophy of Religion', title: 'Problem of Evil', prompt: 'The "logical" problem of evil argues that which three concepts are mutually inconsistent?', correct: 'God is all-powerful, all-good, and evil exists', wrong: [["Evil is real, Hell is real, and people are free", "These could all be true together without a logical contradiction.", "The problem is about the nature of God."], ["God is one, God is three, and God is infinite", "That is a theological puzzle about the Trinity, not the problem of evil.", "Theodicy tries to solve this."], ["Science is true, Religion is true, and Nature is cruel", "While challenging, the \"Problem of Evil\" specifically targets the attributes of a Deity.", "Epicurus framed it as: Is He willing but not able?"]]},
    { id: 16615, chapter: 'Epistemology', title: 'Gettier Cases', prompt: 'Gettier cases are famous in philosophy because they provide counterexamples that show:', correct: 'Justified True Belief is not SUFFICIENT for knowledge', wrong: [["We can never truly know anything (Skepticism)", "Gettier assumed we have knowledge but showed our \"definition\" was wrong.", "You can have JTB but still only have \"luck\"."], ["Justification is unnecessary if you have the truth", "Gettier cases have truth and justification, but still feel like \"not knowledge\".", "The \"luck\" factor is the issue."], ["All beliefs are actually false", "Gettier's subjects have true beliefs.", "Think of the man who \"knows\" the time from a broken clock that happens to be right."]] },
    { id: 16616, chapter: 'Metaphysics', title: 'Determinism vs Compatibilism', prompt: 'A "Compatibilist" believes that:', correct: 'Free will and determinism can both be true at the same time', wrong: [["Free will is an illusion and everything is determined", "That is \"Hard Determinism\".", "Compatibilists \"reconcile\" the two."], ["Human actions are completely random", "Randomness is not free will; free will usually requires some intent.", "Determinism doesn't exclude freedom for them."], ["We have no choice because God knows the future", "That is theological fatalism.", "Think of \"Freedom\" as acting according to your own desires."]] },
    { id: 16617, chapter: 'Philosophy of Mind', title: 'Chinese Room', prompt: 'John Searle\'s \"Chinese Room\" thought experiment is designed to show that:', correct: 'Following a set of rules (syntax) is not the same as understanding (semantics)', wrong: [["Computers will eventually become smarter than humans", "Searle is skeptical that computers \"think\" at all in the human sense.", "Symbols vs Meaning."], ["Translating languages is impossible for machines", "Machines are great at translation, but Searle says they don't \"know\" what the words mean.", "It's a critique of \"Strong AI\"."], ["The brain is just a biological computer", "Searle argues that the brain has \"causal powers\" that simple programs lack.", "A man in a room with a rulebook doesn't speak Chinese."]] },
    { id: 16618, chapter: 'Philosophy of Mind', title: 'Nagel\'s Bat', prompt: 'In his essay \"What Is It Like to Be a Bat?\", Thomas Nagel argues that:', correct: 'Subjective conscious experience cannot be fully captured by objective physical descriptions', wrong: [["Bats have a more complex moral system than humans", "The essay is about consciousness, not ethics.", "Physicalism leaves something out."], ["We should use sonar technology to understand the brain", "Nagel says even if we knew every physical detail of a bat, we wouldn't know the \"feeling\" of being one.", "The \"explanatory gap\"."], ["Animals do not have conscious minds", "Nagel assumes bats ARE conscious; the problem is our inability to access that \"what it\'s likeness\".", "Qualia are subjective."]] },
    { id: 16619, chapter: 'Epistemology', title: 'Problem of Induction', prompt: 'David Hume\'s \"Problem of Induction\" argues that our belief that the future will resemble the past:', correct: 'Cannot be rationally justified by either logic or experience', wrong: [["Is a fundamental law of physics", "Hume says it\'s a \"habit of mind\", not a proven law of reason.", "Circular reasoning problem."], ["Is proven every time the sun rises", "Using the past to prove the future is exactly what is at issue; it\'s circular.", "You can\'t use induction to prove induction."], ["Is a direct revelation from God", "Hume was a naturalist/skeptic on this point.", "Custom is the great guide of life, but not Reason."]] },
    { id: 16620, chapter: 'Political Philosophy', title: 'Veil of Ignorance', prompt: 'John Rawls\' \"Veil of Ignorance\" is a thought experiment where you design a society without knowing:', correct: 'Your own social status, wealth, talents, or identity', wrong: [["What the laws of physics are", "You know general facts about economics and psychology.", "It ensures \"fairness\"."], ["Whether God exists or not", "The veil is about social position and personal \"accidents of birth\".", "Think of a \"neutral\" starting point."], ["How to read or write", "Participants are rational and informed about the world.", "Bias-reduction through ignorance of self."]] },
    { id: 16621, chapter: 'Ethics', title: 'Euthyphro Dilemma', prompt: 'The "Euthyphro Dilemma" asks whether something is good because God loves it, or:', correct: 'God loves it because it is good', wrong: [["God hates it because it is bad", "That is just the inverse, not the other \"horn\" of the dilemma.", "The dilemma is about the source of morality."], ["Bad people think it is good", "This is about the relationship between Divinity and Morality.", "Is morality arbitrary (God\'s whim) or independent (Standard)?"], ["God is the only thing that is good", "This doesn't address whether the \"goodness\" is defined by God\'s will.", "Socrates vs Euthyphro."]] },
    { id: 16622, chapter: 'Philosophy of Mind', title: 'Mary\'s Room', prompt: 'Frank Jackson\'s \"Mary\'s Room\" (the Knowledge Argument) aims to prove that:', correct: 'Physicalism is false because there are non-physical facts about experience', wrong: [["Women are better at science than men", "Mary is a scientist, but the point is about \"qualia\".", "Does she learn something new when she sees red?"], ["Isolation leads to insanity", "The experiment assumes Mary is a brilliant, functioning scientist.", "She knows all physical facts, but lacks the experience."], ["Color is a property of objects, not the mind", "It\'s about whether the \"feeling\" of red is a physical fact.", "Knowledge vs Experience."]] },
    { id: 16623, chapter: 'Metaphysics', title: 'Personal Identity Fission', prompt: 'Derek Parfit\'s \"Fission\" cases (where a person is split into two identical survivors) are used to argue that:', correct: 'Identity is not what matters for survival', wrong: [["We should never use teleporters", "Parfit uses them to challenge our concepts, not to give safety advice.", "Identity is \"all or nothing\", survival can be shared."], ["Souls can be divided like cells", "Parfit is a reductionist/physicalist who doesn't rely on souls.", "The \"self\" is a bundle."], ["You are identical to your brain only", "Fission shows that having \"your\" brain in two bodies makes \"identity\" break down.", "Survival is about psychological continuity."]] },
    { id: 16624, chapter: 'Ethics', title: 'Error Theory', prompt: 'J.L. Mackie\'s \"Error Theory\" about morality claims that:', correct: 'Moral claims are cognitive (aim for truth) but they are all systematically false', wrong: [["Morality is just a matter of personal opinion", "That is subjectivism. Error theory says we \"try\" to speak about objective facts that don't exist.", "Moral facts would be \"queer\"."], ["We should stop caring about right and wrong", "Mackie explains why we have the error, not necessarily that we should abandon all behavior.", "The \"argument from queerness\"."], ["Only scientific facts are true", "Mackie specifically targets moral properties as being unlike anything else in the universe.", "A \"moral fact\" would be an objective \"must-be-done-ness\"."]] },
    { id: 17201, chapter: "Stretch Zone", title: "Epistemology: Gettier Problem", prompt: "Edmund Gettier's famous 1963 paper challenged the traditional definition of knowledge as:", correct: "Justified True Belief (JTB), by showing cases where JTB does not constitute knowledge.", wrong: [["Absolute certainty.", "Descartes focused on certainty; Gettier focused on JTB.", "You can have a justified true belief by pure luck."], ["Empirical observation.", "Gettier's critique was logical, not specifically anti-empiricist.", "Think of the 'man who will get the job has 10 coins in his pocket' example."], ["The scientific method.", "It was a critique of philosophical epistemology.", "He showed JTB is necessary but not sufficient."]] },
    { id: 17202, chapter: "Stretch Zone", title: "Metaphysics: Mind-Body Dualism", prompt: "Descartes' substance dualism asserts that:", correct: "The mind (res cogitans) and the body (res extensa) are fundamentally distinct and separable substances.", wrong: [["The mind is simply an illusion created by the brain.", "That is eliminative materialism.", "Descartes believed the mind was the only thing he could know for certain."], ["The physical universe is all that exists.", "That is physicalism/materialism.", "He posited two realms: thought and extension."], ["Mind and body are two attributes of a single underlying substance.", "That is Spinoza's property dualism/monism.", "Descartes thought they could exist independently."]] },
    { id: 17203, chapter: "Stretch Zone", title: "Ethics: Kant's Categorical Imperative", prompt: "The first formulation of Kant's Categorical Imperative demands that you act only according to a maxim that you can:", correct: "Will to become a universal law of nature.", wrong: [["Use to maximize the greatest good for the greatest number.", "That is utilitarianism.", "Kant was a deontologist; consequences don't matter, duty does."], ["Defend based on your personal cultural values.", "Kant believed ethics were universal and rational, not relativistic.", "If everyone lied, the concept of truth would collapse."], ["Use to achieve your personal goals.", "That is a hypothetical imperative.", "It must apply unconditionally to all rational beings."]] },
    { id: 17204, chapter: "Stretch Zone", title: "Ethics: Utilitarianism", prompt: "According to John Stuart Mill's rule utilitarianism, an action is morally right if:", correct: "It conforms to a rule that, if generally followed, would maximize overall societal happiness.", wrong: [["It maximizes happiness in that specific, isolated instance.", "That is act utilitarianism.", "Mill believed rules protected rights and long-term utility."], ["It fulfills a duty commanded by God.", "That is Divine Command Theory.", "It is still based on consequences (happiness)."], ["It ensures perfect equality of outcomes.", "Utilitarianism maximizes the total sum, it does not guarantee equal distribution.", "Focus on the 'rules'."]] },
    { id: 17205, chapter: "Stretch Zone", title: "Logic: Deductive Validity", prompt: "A deductive argument is considered 'valid' if and only if:", correct: "It is impossible for the premises to be true and the conclusion to be false simultaneously.", wrong: [["The premises are factually true in the real world.", "An argument can be valid with false premises (e.g., 'All pigs fly. I am a pig. I fly.').", "Validity is about the logical structure."], ["The conclusion is likely to be true based on the evidence.", "That describes inductive strength.", "Deduction provides absolute logical guarantees."], ["It is persuasive to a rational audience.", "Rhetoric is about persuasion; logic is about structural truth-preservation.", "Form matters, not content."]] },
    { id: 17206, chapter: "Stretch Zone", title: "Political Philosophy", prompt: "John Rawls uses the 'Veil of Ignorance' thought experiment to ensure that:", correct: "Principles of justice are chosen without bias regarding one's own social position, wealth, or abilities.", wrong: [["The philosopher king retains absolute power.", "That is Plato's Republic.", "Rawls wanted a fair social contract."], ["Everyone is forced to be strictly equal in outcome.", "Rawls allows inequality if it benefits the least advantaged (Difference Principle).", "You don't know who you will be in the society you design."], ["Property rights are established as absolute.", "That is closer to Robert Nozick's libertarianism.", "Justice as Fairness requires impartial deliberation."]] },
    { id: 17207, chapter: "Stretch Zone", title: "Existentialism: Bad Faith", prompt: "For Jean-Paul Sartre, 'bad faith' (mauvaise foi) occurs when a person:", correct: "Denies their radical freedom and acts as if they are an object determined by external circumstances.", wrong: [["Lies to another person for personal gain.", "Bad faith is a lie to oneself about one's ontological freedom.", "Think of the waiter who plays the role of a waiter too perfectly."], ["Believes in God without empirical evidence.", "While Sartre was an atheist, bad faith is specifically about freedom, not just religion.", "Existence precedes essence."], ["Fails to follow the categorical imperative.", "That is Kantian ethics.", "You must take absolute responsibility for your choices."]] },
    { id: 17208, chapter: "Stretch Zone", title: "Philosophy of Science", prompt: "Karl Popper argued that the defining criterion of a scientific theory is its:", correct: "Falsifiability\u2014the capacity to be proven wrong by empirical evidence.", wrong: [["Verifiability\u2014the ability to be proven absolutely true.", "Popper argued you can never prove a universal law true, only false.", "The black swan problem."], ["Consensus\u2014the agreement of the scientific community.", "That is closer to Kuhn's idea of paradigms.", "A theory must make risky predictions."], ["Mathematical elegance.", "Elegance is nice, but empirical testing is the demarcation criterion.", "Psychoanalysis and Marxism failed this test, according to Popper."]] },
    { id: 17209, chapter: "Stretch Zone", title: "Aesthetics", prompt: "According to Kantian aesthetics, a pure judgment of taste must be 'disinterested,' meaning:", correct: "It is not based on any personal desire, utility, or moral interest in the existence of the object.", wrong: [["The viewer finds the artwork boring.", "It means free from bias, not lacking emotion or engagement.", "You appreciate its form for its own sake."], ["The artwork has no commercial value.", "It's about the viewer's psychological state, not the market.", "You do not want to own or consume the object."], ["It is judged purely by its moral message.", "Kant strictly separated aesthetic judgment from moral judgment.", "It is 'purposiveness without a purpose'."]] },
    { id: 17210, chapter: "Stretch Zone", title: "Philosophy of Language", prompt: "In Wittgenstein's later philosophy (Philosophical Investigations), the meaning of a word is defined by:", correct: "Its use within a specific 'language-game,' rather than an inherent connection to an object.", wrong: [["Its logical mapping to a state of affairs in the world.", "That was his early philosophy in the Tractatus Logico-Philosophicus.", "Meaning is social and context-dependent."], ["The dictionary definition determined by experts.", "Wittgenstein believed ordinary use determined meaning.", "Words are tools used in forms of life."], ["An eternal Platonic form it represents.", "He rejected essentialist theories of meaning.", "Think of the concept of a 'game'\u2014it has no single essence, only family resemblances."]] },
  ]),
  dataStructures: makeQuestionBank('University', [
    { id: 16701, chapter: 'Data Structures Dock', title: 'Stack rule', prompt: 'A stack usually follows which rule?', correct: 'Last in, first out', wrong: [['First in, first out', 'That describes a queue.', 'Stacks pop the newest item first.'], ['Random in, random out', 'Standard stacks are not random.', 'Use the LIFO rule.'], ['All in, none out', 'That is not a useful data structure rule.', 'Stacks support push and pop.']] },
    { id: 16702, chapter: 'Data Structures Reef', title: 'Queue rule', prompt: 'A queue usually follows which rule?', correct: 'First in, first out', wrong: [['Last in, first out', 'That is stack behavior.', 'Queues process oldest items first.'], ['Only numbers allowed', 'Queues can store many data types.', 'The rule is about order, not type.'], ['Everything at once', 'Queues process in sequence.', 'Think line at a ticket booth.']] },
    { id: 16703, chapter: 'Data Structures Cove', title: 'Tree clue', prompt: 'A tree data structure is useful when data has:', correct: 'Parent-child relationships', wrong: [['Only one value forever', 'Trees hold structured collections, not a single fixed value.', 'Think branching relationships.'], ['No hierarchy at all', 'Trees are explicitly hierarchical.', 'Hierarchy is the clue.'], ['Only circular edges every time', 'Cycles are not the core tree property.', 'Trees are branching, not cyclic by default.']] },
    { id: 16704, chapter: 'Data Structures Lagoon', title: 'Hash map strength', prompt: 'Why are hash maps often useful?', correct: 'They support fast lookup by key', wrong: [['They always sort data alphabetically', 'Hash maps are not mainly sorting tools.', 'Their strength is keyed access.'], ['They remove the need for memory', 'They still use memory.', 'Speed comes with storage tradeoffs.'], ['They can only store one item', 'Hash maps store many key-value pairs.', 'Think lookup by key.']] },
    { id: 16705, chapter: "Complexity Analysis", title: "Merge Sort Time Complexity", prompt: "What is the Big-O time complexity of a recursive algorithm described by the recurrence relation T(n) = 2T(n/2) + O(n)?", correct: "O(n log n)", wrong: [["O(n^2)", "This would happen if T(n) = T(n-1) + O(n).", "Think of a tree of depth log(n) where each level does O(n) work."], ["O(n)", "This would be T(n) = T(n/2) + O(1).", "The work isn't halving; it's branching."], ["O(log n)", "This is binary search.", "You process all n elements at each level."]] },
    { id: 16706, chapter: "Linked Lists", title: "Cycle Detection", prompt: "Which algorithm is commonly used to detect a cycle or loop in a singly linked list with O(1) space complexity?", correct: "Floyd's Cycle-Finding Algorithm (Tortoise and Hare)", wrong: [["Dijkstra's Algorithm", "Dijkstra is for shortest paths in graphs.", "Think of two pointers moving at different speeds."], ["Kruskal's Algorithm", "Kruskal is for Minimum Spanning Trees.", "It involves a fast pointer and a slow pointer."], ["Breadth-First Search", "BFS uses a queue, which requires O(n) space.", "We need O(1) space."]] },
    { id: 16707, chapter: "Hash Tables", title: "Open Addressing", prompt: "In open addressing, which collision resolution technique is most vulnerable to primary clustering?", correct: "Linear Probing", wrong: [["Quadratic Probing", "Quadratic probing suffers from secondary clustering, not primary.", "Primary clustering is when sequential gaps fill up and merge into large blocks."], ["Double Hashing", "Double hashing avoids both primary and secondary clustering well.", "This technique simply steps forward by 1."], ["Chaining", "Chaining uses linked lists, not open addressing.", "It's the simplest probing method."]] },
    { id: 16708, chapter: "Trees", title: "BST Deletion", prompt: "When deleting a node with two children in a Binary Search Tree (BST), you must replace it with:", correct: "Its in-order successor or in-order predecessor", wrong: [["Its left child", "The left child might have a right subtree that would violate BST properties.", "You need the next largest or next smallest value."], ["The root of the tree", "Replacing it with the root would destroy the tree structure.", "Find a leaf or a node with one child to swap."], ["A newly created null node", "You can't just delete it; you must maintain the tree structure for the children.", "Look for the minimum value in the right subtree."]] },
    { id: 16709, chapter: "Trees", title: "AVL Rotations", prompt: "In an AVL tree, if an insertion occurs in the right subtree of the left child of an unbalanced node, which rotation is required?", correct: "Left-Right (LR) Rotation", wrong: [["Single Right (LL) Rotation", "LL is used for an insertion in the left subtree of the left child.", "The insertion path 'zig-zags' (Left then Right)."], ["Single Left (RR) Rotation", "RR is for the right subtree of the right child.", "It requires a double rotation."], ["Right-Left (RL) Rotation", "RL is for an insertion in the left subtree of the right child.", "Match the path: Left child, Right subtree."]] },
    { id: 16710, chapter: "Heaps", title: "Building a Heap", prompt: "What is the worst-case time complexity of building a binary heap from an unsorted array using the optimal 'heapify' (bottom-up) approach?", correct: "O(n)", wrong: [["O(n log n)", "This is the time it takes to sort using a heap, or build it by inserting n elements one by one.", "The bottom-up approach is mathematically faster."], ["O(n^2)", "Heap operations are bounded by the height of the tree (log n).", "Most nodes are near the bottom and don't need to sift down far."], ["O(log n)", "You have to process all n elements, so it can't be faster than O(n).", "Think of the sum of heights of all nodes."]] },
    { id: 16711, chapter: "Graphs", title: "Graph Representation", prompt: "When is an Adjacency Matrix preferred over an Adjacency List?", correct: "When the graph is dense and edge existence queries are frequent", wrong: [["When the graph is very sparse", "A matrix would waste a lot of space (O(V^2)) for a sparse graph.", "Think about memory efficiency vs query speed."], ["When you need to iterate over all neighbors quickly", "An adjacency list is faster for iterating over neighbors.", "A matrix allows O(1) checks for a specific edge."], ["When memory space is severely limited", "A matrix uses O(V^2) memory regardless of edges, which is bad for limited memory.", "Dense graphs have edges approaching V^2."]] },
    { id: 16712, chapter: "Graphs", title: "Dijkstra's Algorithm", prompt: "Why does standard Dijkstra's algorithm fail with negative edge weights?", correct: "It assumes that once a node's shortest path is finalized, it cannot be reduced by subsequent longer paths", wrong: [["It cannot process floating-point numbers", "Edge weights can be any numerical type.", "It's a greedy algorithm."], ["It uses a stack instead of a queue", "Dijkstra uses a priority queue.", "The greedy choice assumes adding edges only increases total cost."], ["It requires the graph to be a tree", "Dijkstra works on general graphs with cycles.", "Negative edges allow a path to get 'shorter' by adding more edges."]] },
    { id: 16713, chapter: "Graphs", title: "Minimum Spanning Trees", prompt: "Kruskal's algorithm for finding a Minimum Spanning Tree typically uses which data structure to efficiently detect cycles?", correct: "Disjoint Set (Union-Find)", wrong: [["Priority Queue", "While it uses a priority queue/sort for edges, the cycle detection is done elsewhere.", "It needs to track connected components."], ["Hash Table", "Hash tables don't easily track merging sets.", "Think of operations like 'find' and 'union'."], ["Binary Search Tree", "A BST is too slow for merging sets of vertices.", "It keeps track of which vertices are in which tree."]] },
    { id: 16714, chapter: "Stretch Zone", title: "Disjoint Sets", prompt: "In a Disjoint Set data structure, the 'path compression' optimization ensures that:", correct: "Nodes along the path of a 'Find' operation are attached directly to the root", wrong: [["The height of the tree is always exactly 2", "The height is flattened, but not strictly guaranteed to be exactly 2 instantly.", "It flattens the tree to speed up future operations."], ["All sets are merged into one single set", "Union operations merge sets, path compression just flattens them.", "It optimizes the 'Find' step."], ["Memory usage is compressed by removing unused nodes", "Nodes are never removed; the pointers are just updated.", "It makes subsequent 'Find' calls O(1) amortized."]] },
  ]),
  internationalRelations: makeQuestionBank('University', [
    { id: 16801, chapter: 'IR Dock', title: 'State actor', prompt: 'In international relations, a state usually means:', correct: 'A politically organized sovereign country', wrong: [['A temporary mood', 'That is not the IR meaning.', 'State here means political entity.'], ['Only one city block', 'That is too small and not sovereign.', 'Think country-level actor.'], ['Any weather pattern', 'That is unrelated.', 'Use the political definition.']] },
    { id: 16802, chapter: 'IR Reef', title: 'Diplomacy role', prompt: 'Diplomacy is mainly about:', correct: 'Managing relations and negotiation between political actors', wrong: [['Only military invasion', 'That is force, not diplomacy.', 'Diplomacy emphasizes communication and bargaining.'], ['Ignoring all other countries', 'That blocks relations rather than managing them.', 'It is about engagement.'], ['Writing poetry about maps', 'That is not the core practice.', 'Use the negotiation idea.']] },
    { id: 16803, chapter: 'IR Cove', title: 'Alliance idea', prompt: 'An alliance is usually:', correct: 'An agreement for cooperation between states', wrong: [['A type of weather emergency', 'That is unrelated.', 'Alliances are political agreements.'], ['A private hobby club only', 'International alliances involve states or major actors.', 'Think coordinated cooperation.'], ['A border drawn with crayons', 'That is not the main definition.', 'Use the agreement idea.']] },
    { id: 16804, chapter: 'IR Lagoon', title: 'Soft power', prompt: 'Soft power refers to influence through:', correct: 'Attraction, persuasion, and cultural appeal', wrong: [['Only tanks and missiles', 'That is hard power.', 'Soft power works through attraction and legitimacy.'], ['A stronger concrete mixture', 'That is unrelated.', 'Think influence without coercion.'], ['Random luck', 'Soft power is not just accident.', 'It is a form of political influence.']] },
    { id: 16805, chapter: "Grand Theories", title: "Structural Realism", prompt: "According to Kenneth Waltz's structural realism (neorealism), state behavior is primarily determined by:", correct: "The anarchic structure of the international system and the distribution of capabilities", wrong: [["The personal morality of state leaders", "This is closer to classical realism (human nature) or constructivism.", "Structural realism ignores domestic politics."], ["The type of economic system within a state", "This is a Marxist or liberal view.", "It focuses on the 'structure' of the system."], ["The influence of international organizations like the UN", "Realists believe international organizations are just tools of powerful states.", "Anarchy means there is no global 911."]] },
    { id: 16806, chapter: "Grand Theories", title: "Democratic Peace Theory", prompt: "The core mechanism behind Democratic Peace Theory (the observation that democracies rarely fight each other) is thought to be:", correct: "Institutional constraints (checks and balances) and shared norms of peaceful conflict resolution", wrong: [["Democracies have smaller militaries than autocracies", "Democracies often have very powerful militaries.", "It's about how leaders are held accountable."], ["Authoritarian leaders are biologically more aggressive", "The theory is based on institutions, not biology.", "Think about elections and public opinion."], ["Capitalism makes war unprofitable", "While related (commercial peace), the specific democratic peace focuses on governance.", "It's about the political system's structure."]] },
    { id: 16807, chapter: "Grand Theories", title: "Constructivism", prompt: "Alexander Wendt's famous phrase 'Anarchy is what states make of it' implies that:", correct: "Anarchy does not inherently dictate self-help; its effects depend on shared ideas and identities", wrong: [["There is a global government secretly controlling anarchy", "Constructivism does not claim a secret world government.", "It focuses on social construction."], ["States can easily vote to eliminate anarchy", "Anarchy is a structural fact, but its meaning is fluid.", "Think about how enemies view each other vs how allies do."], ["Anarchy only exists in failing states", "Anarchy in IR means the lack of a supreme global authority, which applies everywhere.", "Ideas matter as much as material power."]] },
    { id: 16808, chapter: "Foreign Policy", title: "Bureaucratic Politics", prompt: "The Bureaucratic Politics Model (Allison's Model III) suggests that foreign policy decisions are:", correct: "The result of bargaining, pulling, and hauling between different government agencies", wrong: [["Calculated choices made by a single rational actor maximizing national interest", "This is the Rational Actor Model (Model I).", "Think 'where you stand depends on where you sit'."], ["Dictated entirely by public opinion polls", "Bureaucracies often insulate themselves from direct public opinion.", "It focuses on internal government dynamics."], ["Random decisions based on the mood of the leader", "Decisions are highly structured by organizational routines and interests.", "Agencies fight for budget and influence."]] },
    { id: 16809, chapter: "Foreign Policy", title: "Nuclear Deterrence", prompt: "For Mutually Assured Destruction (MAD) to be a stable deterrent, both opposing states must possess:", correct: "A secure second-strike capability", wrong: [["An overwhelming first-strike advantage", "If one has a first-strike advantage, MAD fails because they can win a nuclear war.", "Both sides must know they will be destroyed even if they attack first."], ["A comprehensive missile defense system", "Perfect missile defense would actually undermine MAD by making retaliation impossible.", "Vulnerability is key to MAD."], ["Equal numbers of conventional ground troops", "Nuclear deterrence relies on nuclear weapons, not conventional forces.", "The ability to retaliate after being hit."]] },
    { id: 16810, chapter: "International Law", title: "Responsibility to Protect", prompt: "The 'Responsibility to Protect' (R2P) doctrine fundamentally challenges which traditional Westphalian concept?", correct: "Absolute state sovereignty and non-interference in domestic affairs", wrong: [["The balance of power", "R2P is a human rights norm, not a power-balancing strategy.", "It involves intervening inside another country's borders."], ["Free trade and globalization", "R2P is about atrocities, not economics.", "Westphalia established that a king rules his own territory exclusively."], ["Nuclear non-proliferation", "R2P applies to conventional atrocities and genocide.", "It redefines sovereignty as a responsibility, not a right."]] },
    { id: 16811, chapter: "International Law", title: "UN Security Council", prompt: "A major structural limitation of the UN Security Council in resolving conflicts involving major powers is:", correct: "The veto power held by the five permanent members (P5)", wrong: [["It has no military force to deploy", "The UN can deploy peacekeepers, though they are borrowed.", "The problem is decision-making paralysis."], ["It must get unanimous approval from all 193 member states", "That is the General Assembly's realm, and even they don't require unanimity.", "Only 5 countries have this special power."], ["It only meets once a year", "The Security Council is designed to function continuously.", "Any of the five winners of WWII can block a resolution."]] },
    { id: 16812, chapter: "International Political Economy", title: "Bretton Woods", prompt: "The Bretton Woods system (established in 1944) was originally designed to:", correct: "Establish a stable international monetary system based on fixed exchange rates pegged to the US dollar", wrong: [["Create a global military alliance against the Soviet Union", "That was NATO. Bretton Woods was economic.", "It created the IMF and World Bank."], ["Dismantle all tariffs and implement immediate global free trade", "GATT aimed to reduce tariffs, but the system allowed for controlled economies.", "It focused on monetary stability to prevent another Great Depression."], ["Fund the colonization of the developing world", "It was designed to rebuild post-war Europe and stabilize global finance.", "Think 'gold standard' and 'exchange rates'."]] },
    { id: 16813, chapter: "International Political Economy", title: "Comparative Advantage", prompt: "According to the theory of Comparative Advantage, free trade benefits two countries even if one is less efficient at producing everything because:", correct: "They can specialize in producing goods where their relative opportunity cost is lowest", wrong: [["The wealthier country will just give money to the poorer one", "Trade is about exchange, not charity.", "It's about relative efficiency, not absolute efficiency."], ["Tariffs will automatically balance the trade deficit", "Free trade theories usually oppose tariffs.", "Think about what a country is 'least bad' at producing."], ["The global supply of gold increases", "This is a mercantilist view.", "Specialization increases total global output."]] },
    { id: 16814, chapter: "Contemporary Challenges", title: "Hegemonic Stability", prompt: "According to Hegemonic Stability Theory, a liberal, open international economy is most likely to flourish when:", correct: "A single dominant global power is willing and able to enforce the rules of the system", wrong: [["Power is distributed equally among a dozen regional powers", "The theory claims multipolarity leads to protectionism and instability.", "It requires a 'hegemon'."], ["The United Nations is given absolute control over global trade", "The theory focuses on state power, not international organizations.", "Think of the British Empire in the 19th century or the US post-WWII."], ["All states adopt a strict mercantilist policy", "Mercantilism is the opposite of an open, liberal economy.", "One country bears the costs of keeping the system open."]] },
  ]),
  marketing: makeQuestionBank('University', [
    { id: 16901, chapter: 'Marketing Dock', title: 'Target audience', prompt: 'A target audience is:', correct: 'The group a message or product is mainly aimed at', wrong: [['Every person on Earth equally', 'Some products are broad, but target audience means a defined group.', 'Think specific intended audience.'], ['Only the people inside one shop at noon', 'That is too narrow and accidental.', 'Targeting is strategic, not random.'], ['The font used in an ad', 'That is design, not audience definition.', 'Focus on who the message is for.']] },
    { id: 16902, chapter: 'Marketing Reef', title: 'Brand role', prompt: 'A brand mainly helps customers:', correct: 'Recognize and form expectations about a product or company', wrong: [['Avoid making any decisions', 'Brands often guide decisions rather than remove them.', 'Recognition and trust are key roles.'], ['Measure rainfall', 'That is unrelated.', 'Think identity and expectation.'], ['Turn off all competition', 'Brand strength helps, but does not erase competition.', 'Use the recognition idea.']] },
    { id: 16903, chapter: 'Marketing Cove', title: 'Value proposition', prompt: 'A value proposition explains:', correct: 'Why a customer should choose a product', wrong: [['Only the office Wi-Fi password', 'That is unrelated.', 'Value propositions state customer benefit.'], ['How tall the CEO is', 'That is not the key buying reason.', 'Focus on customer value.'], ['The complete legal code of a country', 'That is irrelevant.', 'Use the benefit-and-choice idea.']] },
    { id: 16904, chapter: 'Marketing Lagoon', title: 'Conversion clue', prompt: 'A conversion usually means:', correct: 'A user took the action you wanted them to take', wrong: [['A spreadsheet changed color', 'That is not a standard marketing conversion.', 'Think desired action like sign-up or purchase.'], ['Every visitor left immediately', 'That is the opposite of many conversion goals.', 'Use the goal-completion idea.'], ['The logo moved one pixel', 'That is unrelated.', 'Conversion is about user behavior.']] },
    { id: 16905, chapter: "Strategy", title: "BCG Matrix", prompt: "In the BCG Growth-Share Matrix, a 'Question Mark' represents a product or business unit with:", correct: "Low market share in a high-growth market", wrong: [["High market share in a low-growth market", "This is a 'Cash Cow'.", "It requires heavy investment to gain share."], ["Low market share in a low-growth market", "This is a 'Dog'.", "The market is growing, but the product isn't keeping up yet."], ["High market share in a high-growth market", "This is a 'Star'.", "Management must decide whether to invest to make it a Star, or phase it out."]] },
    { id: 16906, chapter: "Strategy", title: "Macroenvironment", prompt: "A PESTLE analysis is a strategic tool primarily used to evaluate:", correct: "External macro-environmental factors (Political, Economic, etc.) that can impact a business", wrong: [["Internal company strengths and weaknesses", "This is part of a SWOT analysis.", "These are factors the company cannot directly control."], ["The effectiveness of a specific advertising campaign", "PESTLE is a high-level strategic tool.", "It looks at the 'big picture' world trends."], ["The individual psychological traits of a target customer", "This is psychographic segmentation.", "Think global forces."]] },
    { id: 16907, chapter: "Consumer Behavior", title: "Cognitive Dissonance", prompt: "In marketing, post-purchase 'cognitive dissonance' refers to:", correct: "Inner tension or doubt a consumer feels about whether they made the right purchase decision", wrong: [["The feeling of extreme joy after buying a luxury item", "Dissonance means disharmony or discomfort.", "Buyer's remorse."], ["The inability to remember an advertisement", "That's just forgetting.", "It happens *after* the purchase of a high-involvement item."], ["When a product breaks immediately after the warranty expires", "This causes anger, but dissonance is psychological conflict.", "Did I buy the right brand?"]] },
    { id: 16908, chapter: "Market Research", title: "Primary Data", prompt: "Which of the following is a key advantage of collecting primary data over secondary data?", correct: "It is specifically tailored to answer the exact research problem at hand", wrong: [["It is always much cheaper to collect", "Primary data (like focus groups or surveys) is usually much more expensive.", "You gather it yourself."], ["It is instantly available online", "Secondary data is what you find online; primary data takes time to gather.", "It answers YOUR specific question."], ["It requires no ethical review", "Surveying or observing people often requires ethical considerations.", "It's fresh data."]] },
    { id: 16909, chapter: "Segmentation", title: "Psychographic Segmentation", prompt: "Psychographic segmentation divides a market based on variables such as:", correct: "Lifestyle, personality traits, values, and interests", wrong: [["Age, gender, income, and education", "These are demographic variables.", "It goes beyond 'who' they are to 'why' they buy."], ["City, climate, and population density", "These are geographic variables.", "Think about a consumer's psychology."], ["Usage rate and brand loyalty", "These are behavioral variables.", "It categorizes people by their attitudes and activities."]] },
    { id: 16910, chapter: "Segmentation", title: "Perceptual Mapping", prompt: "A perceptual map is a visual tool typically used in marketing to:", correct: "Display the perceptions of customers regarding different brands relative to competitors along key dimensions", wrong: [["Track the physical GPS location of delivery trucks", "It's a map of the mind, not geography.", "It shows how a brand is 'positioned'."], ["Graph the company's revenue over the last decade", "That is a line chart.", "It usually has an X and Y axis for attributes (e.g., Price vs Quality)."], ["Map out the organizational hierarchy of a marketing department", "That is an org chart.", "It helps identify gaps in the market."]] },
    { id: 16911, chapter: "Product and Pricing", title: "Penetration Pricing", prompt: "The strategy of 'penetration pricing' involves setting an initially low price in order to:", correct: "Rapidly gain market share and achieve high sales volume before competitors react", wrong: [["Maximize short-term profit margins on each unit sold", "That is price skimming.", "Low prices mean low margins, but high volume."], ["Signal to consumers that the product is a luxury, premium item", "Low prices usually signal the opposite of luxury.", "The goal is to 'penetrate' the market deeply."], ["Recover research and development costs immediately", "Skimming is used for quick cost recovery.", "It relies on economies of scale."]] },
    { id: 16912, chapter: "Promotion", title: "PR vs Advertising", prompt: "A primary difference between advertising and public relations (PR) is that PR is typically:", correct: "Unpaid, earned media coverage focused on building a positive corporate image", wrong: [["Paid media placement with guaranteed messaging control", "That defines advertising.", "PR relies on journalists finding the story interesting."], ["Focused only on short-term sales promotions like coupons", "That is sales promotion.", "PR is about reputation."], ["Only used during a corporate crisis or scandal", "PR is a continuous effort to manage image.", "Think of a press release vs a TV commercial."]] },
    { id: 16913, chapter: "Metrics", title: "CAC and LTV", prompt: "For a business to be highly profitable and sustainable, its Customer Acquisition Cost (CAC) should ideally be:", correct: "Significantly lower than the Customer Lifetime Value (LTV)", wrong: [["Exactly equal to the Customer Lifetime Value (LTV)", "If they are equal, the company makes zero profit on the customer.", "You want to make more money from them than you spent to get them."], ["Significantly higher than the Customer Lifetime Value (LTV)", "This means the company is losing money on every customer.", "A common ratio target is LTV:CAC = 3:1."], ["Calculated without factoring in marketing expenses", "CAC is literally the calculation of marketing/sales expenses divided by new customers.", "Cost vs Value."]] },
    { id: 16914, chapter: "Stretch Zone", title: "The Decoy Effect", prompt: "In behavioral economics, the 'decoy effect' in pricing is a strategy where:", correct: "An inferior third option is presented to make one of the other options look like a much better value", wrong: [["Prices are hidden until the customer reaches the checkout", "That is drip pricing or hidden fees.", "Think of the small, medium, and large popcorn pricing at movies."], ["A fake product is advertised that the company never intends to sell", "That is closer to bait-and-switch.", "The decoy is an actual option, just a bad one."], ["The price is set just below a round number (e.g., $9.99 instead of $10.00)", "That is psychological or charm pricing.", "It relies on asymmetric dominance."]] },
  ])
  }
}
